// ── Call Timeline: search sessions by email / userId / sessionId ─────────────
app.get("/admin/voice/diag/timeline", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const q = z.object({ q: z.string().min(1).max(100) }).parse(req.query || {});
  const term = q.q.trim();

  // Resolve userId(s) from the search term
  let userIds: string[] = [];
  let sessionIds: string[] = [];

  // If looks like a session CUID
  if (/^c[a-z0-9]{20,}$/i.test(term)) {
    sessionIds = [term];
  } else if (term.includes("@")) {
    // Email lookup
    const user = await db.user.findFirst({ where: { email: { contains: term } }, select: { id: true } });
    if (user) userIds = [user.id];
  } else {
    // Try as userId
    userIds = [term];
  }

  const where: Record<string, unknown> = {};
  if (sessionIds.length) where.id = { in: sessionIds };
  else if (userIds.length) where.userId = { in: userIds };
  else return { sessions: [] };

  const sessions = await db.voiceClientSession.findMany({
    where,
    orderBy: { startedAt: "desc" },
    take: 20,
    include: {
      events: { orderBy: { createdAt: "asc" }, take: 200 },
      user: { select: { email: true } },
    },
  });

  return {
    sessions: sessions.map((s) => ({
      id: s.id,
      userId: s.userId,
      userEmail: (s as any).user?.email ?? s.userId,
      platform: s.platform,
      startedAt: s.startedAt.toISOString(),
      endedAt: s.endedAt?.toISOString() ?? null,
      lastRegState: s.lastRegState,
      lastCallState: s.lastCallState,
      iceHasTurn: s.iceHasTurn,
      events: ((s as any).events ?? []).map((e: any) => ({
        id: e.id,
        type: e.type,
        createdAt: e.createdAt.toISOString(),
        payload: e.payload as Record<string, unknown>,
      })),
    })),
  };
});

// ── AI Diagnostics: plain-English explanation of a session ───────────────────
app.post("/admin/voice/diag/explain", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const input = z.object({ sessionId: z.string().min(1).max(100) }).parse(req.body || {});

  const session = await db.voiceClientSession.findUnique({
    where: { id: input.sessionId },
    include: { events: { orderBy: { createdAt: "asc" }, take: 200 } },
  });

  if (!session) return reply.status(404).send({ error: "Session not found" });

  const events = (session as any).events as Array<{ type: string; createdAt: Date; payload: unknown }>;

  // Pull the most recent quality report (may have RCA inside)
  const qualityEvent = [...events].reverse().find((e) => e.type === "CALL_QUALITY_REPORT");
  const qp = qualityEvent ? (qualityEvent.payload as Record<string, unknown>) : null;
  const rca = qp?.rca as Record<string, unknown> | undefined;

  // Gather signal facts
  const hasIceFailure = events.some((e) => e.type === "ICE_SELECTED_PAIR") === false
    && events.some((e) => e.type === "CALL_CONNECTED") === false
    && events.some((e) => e.type === "INCOMING_INVITE") === true;
  const callConnected = events.some((e) => e.type === "CALL_CONNECTED");
  const callEnded = events.some((e) => e.type === "CALL_ENDED");
  const wsDisconnected = events.some((e) => e.type === "WS_DISCONNECTED");
  const errorEvents = events.filter((e) => e.type === "ERROR");
  const grade = qp ? String(qp.qualityGrade ?? "") : null;
  const hasTurn = session.iceHasTurn;
  const isRelay = qp?.isUsingRelay === true;
  const rttMs = typeof qp?.rttMs === "number" ? qp.rttMs : null;
  const jitterMs = typeof qp?.jitterMs === "number" ? qp.jitterMs : null;
  const packetsLost = typeof qp?.packetsLost === "number" ? qp.packetsLost : null;
  const remoteAudioReceiving = qp?.remoteAudioReceiving !== false;
  const answeredCount = events.filter((e) => e.type === "ANSWER_TAPPED").length;
  const platform = session.platform;

  // Build plain-English explanation from evidence
  type Explanation = {
    summary: string;
    whatHappened: string;
    likelyCause: string;
    suggestedFix: string;
    confidence: string;
    grade: string | null;
  };

  function explain(): Explanation {
    const cause = rca?.primaryCause as string | undefined;
    const confidence = String(rca?.confidence ?? "LOW");
    const suggestion = rca?.suggestedAction as string | undefined;

    const fixMap: Record<string, string> = {
      enable_TURN_relay: "Configure a TURN server in Voice → Settings → WebRTC. TURN is required for callers behind strict NAT or corporate firewalls.",
      adjust_PBX_NAT_config: "Check the PBX NAT/RTP settings and ensure externip/localnet are configured correctly.",
      avoid_Bluetooth_on_device: "The user should avoid Bluetooth headsets for calls, or ensure the Bluetooth audio profile is correct.",
      improve_network: "The caller should move to a better network connection (WiFi vs cellular, or closer to the router).",
      investigate_firewall: "Check firewall rules — UDP ports 10000–20000 may be blocked. Try adding a TURN server with TCP on port 443.",
      investigate_PBX_media_path: "Check the PBX RTP engine settings, especially if the call goes through a trunk with different codecs.",
      check_codec_config: "Verify the PBX is set to prefer Opus for WebRTC calls.",
      check_client_network: "The caller may have poor internet connectivity. Advise them to switch networks.",
      none: "No specific action required — monitor for recurrence.",
    };

    const fixText = suggestion ? (fixMap[suggestion] ?? suggestion.replace(/_/g, " ")) : "No specific fix identified — review the event timeline for clues.";

    // Override causes for special cases
    if (!callConnected && answeredCount > 0) {
      return {
        summary: "Call was answered but never connected",
        whatHappened: `The user tapped Answer ${answeredCount} time(s) but the call never reached a connected state. ${wsDisconnected ? "The SIP WebSocket also disconnected during the session." : ""}`,
        likelyCause: hasTurn
          ? "ICE negotiation likely stalled — media could not be established even with TURN. This may be a PBX media path or firewall issue."
          : "No TURN server is configured. ICE could not find a viable media path through the caller's NAT. The call rang but audio was never established.",
        suggestedFix: hasTurn
          ? "Check firewall/UDP ports on the TURN server and verify PBX RTP engine settings."
          : "Configure a TURN server in Voice → Settings → WebRTC.",
        confidence: hasTurn ? "MEDIUM" : "HIGH",
        grade,
      };
    }

    if (errorEvents.length > 0 && !callConnected) {
      const errMsg = String((errorEvents[0].payload as Record<string, unknown>)?.message ?? "unknown error");
      return {
        summary: "Session ended with error before call connected",
        whatHappened: `The session encountered ${errorEvents.length} error(s). Most recent: "${errMsg}". The call did not reach a connected state.`,
        likelyCause: errMsg.toLowerCase().includes("ice") || errMsg.toLowerCase().includes("candidate")
          ? "ICE negotiation failed — the browser and PBX could not establish a media path."
          : errMsg.toLowerCase().includes("register") || errMsg.toLowerCase().includes("sip")
          ? "SIP registration failed, preventing the call from proceeding."
          : "An application error occurred during call setup.",
        suggestedFix: fixText,
        confidence: "MEDIUM",
        grade,
      };
    }

    if (cause === "ICE_failure") {
      return {
        summary: "Call failed — ICE connection could not be established",
        whatHappened: `The WebRTC ICE negotiation failed. This means the browser and the PBX could not find a media path to exchange audio. ${hasTurn ? "TURN was configured but still failed." : "No TURN relay was available."}`,
        likelyCause: hasTurn
          ? "TURN is configured but ICE still failed — the TURN server or PBX firewall may be blocking the media path."
          : "No TURN server is configured. The browser is behind NAT and cannot reach the PBX directly.",
        suggestedFix: hasTurn ? "Verify TURN server UDP/TCP ports (3478, 5349, 443) are open. Check TURN credentials." : "Configure a TURN relay server in Voice → Settings → WebRTC.",
        confidence: "HIGH",
        grade,
      };
    }

    if (cause === "TURN_missing") {
      return {
        summary: `Audio quality degraded — no TURN relay used`,
        whatHappened: `The call connected but quality was ${grade ?? "degraded"}. ${rttMs !== null ? `RTT was ${rttMs}ms` : ""}${jitterMs !== null ? `, jitter ${jitterMs}ms` : ""}. The call used a direct ICE path without TURN relay.`,
        likelyCause: "The caller is behind NAT and the direct ICE path introduced high latency or packet loss. Using TURN relay would route audio through the server and stabilize the connection.",
        suggestedFix: "Enable and configure a TURN server for this tenant. This is the single most impactful fix for audio quality over remote networks.",
        confidence: "HIGH",
        grade,
      };
    }

    if (cause === "one_way_audio" || !remoteAudioReceiving) {
      return {
        summary: "One-way audio — remote party could not be heard",
        whatHappened: `The call connected but no incoming audio was received${packetsLost !== null ? ` (${packetsLost} packets lost)` : ""}. The caller's browser was transmitting but not receiving.`,
        likelyCause: isRelay
          ? "RTP is going through TURN but no audio is arriving. This may be a PBX media path or codec mismatch issue."
          : "No TURN relay — the outbound RTP stream may be reaching the PBX but the return path is blocked by NAT.",
        suggestedFix: isRelay ? "Check the PBX RTP engine and Opus codec configuration." : "Configure a TURN relay server to ensure bidirectional RTP flow.",
        confidence: packetsLost === 0 ? "HIGH" : "MEDIUM",
        grade,
      };
    }

    if (cause === "high_jitter" || (jitterMs !== null && jitterMs > 50)) {
      return {
        summary: `Audio choppy — high jitter (${jitterMs}ms)`,
        whatHappened: `The call connected and audio flowed, but jitter was ${jitterMs}ms (normal is <20ms). This typically causes choppy, robotic, or breaking audio.`,
        likelyCause: platform === "IOS" || platform === "ANDROID"
          ? "The mobile device may have been on a poor cellular or WiFi signal, causing variable packet delivery."
          : "Network instability on the caller's internet connection — possibly WiFi interference or a congested link.",
        suggestedFix: "Advise the caller to use a stable wired or strong WiFi connection. Consider enabling TURN with TCP on port 443 as a fallback.",
        confidence: (jitterMs ?? 0) > 80 ? "HIGH" : "MEDIUM",
        grade,
      };
    }

    if (cause === "packet_loss" || (packetsLost !== null && packetsLost > 20)) {
      return {
        summary: `Audio quality poor — significant packet loss (${packetsLost} packets)`,
        whatHappened: `${packetsLost} audio packets were lost during the call. This causes audible gaps, clicks, and distortion.`,
        likelyCause: isRelay
          ? "Packet loss is occurring despite TURN relay — the caller's internet connection may have quality issues."
          : "Network congestion or an unstable path. Without TURN relay, the RTP path traverses multiple NAT hops.",
        suggestedFix: isRelay ? "Advise the caller to improve their network connection." : "Enable TURN relay to take the RTP path through a stable server.",
        confidence: "HIGH",
        grade,
      };
    }

    if (wsDisconnected && !callConnected) {
      return {
        summary: "SIP WebSocket disconnected before call could connect",
        whatHappened: "The SIP WebSocket connection dropped during the session. This prevented call signaling from completing.",
        likelyCause: "Network interruption, proxy timeout, or PBX WebSocket server instability.",
        suggestedFix: "Check the PBX WSS transport on port 8089. Verify nginx proxy_read_timeout is not set too low for SIP keep-alives.",
        confidence: "MEDIUM",
        grade,
      };
    }

    if (callConnected && callEnded && (grade === "excellent" || grade === "good")) {
      return {
        summary: "Call completed successfully with good quality",
        whatHappened: `The call was established and completed normally. ${rttMs !== null ? `RTT: ${rttMs}ms` : ""}${jitterMs !== null ? `, jitter: ${jitterMs}ms` : ""}. ${isRelay ? "TURN relay was used." : "Direct ICE path was used."}`,
        likelyCause: "No issues detected in this session.",
        suggestedFix: "No action required.",
        confidence: "HIGH",
        grade,
      };
    }

    // Generic fallback
    return {
      summary: `Session ended — quality: ${grade ?? "unknown"}`,
      whatHappened: `The session had ${events.length} events. Call ${callConnected ? "connected" : "did not connect"}${callEnded ? " and ended normally" : ""}. ${errorEvents.length > 0 ? `${errorEvents.length} error(s) occurred.` : ""}`,
      likelyCause: cause ? `The RCA engine identified: ${cause.replace(/_/g, " ")} (${confidence} confidence).` : "Not enough data to determine the root cause automatically. Review the event timeline above.",
      suggestedFix: fixText,
      confidence,
      grade,
    };
  }

  return explain();
});

// ════════════════════════════════════════════════════════════════════════════════
// CALL FLIGHT RECORDER
// Mobile uploads a full structured call timeline (one session per call).
// Admin panel queries and diagnoses sessions.
// ════════════════════════════════════════════════════════════════════════════════

// ── Mobile upload: POST /mobile/flight-recorder/upload ───────────────────────
app.post("/mobile/flight-recorder/upload", async (req, reply) => {
  const auth = getUser(req);

  const body = req.body as { session?: unknown; stats?: unknown };
  if (!body?.session || typeof body.session !== "object") {
    return reply.status(400).send({ error: "Missing session" });
  }

  const session = body.session as Record<string, unknown>;
  const stats = (body.stats ?? {}) as Record<string, unknown>;

  // Validate required fields
  const sessionId = String(session.id || "").slice(0, 64);
  if (!sessionId) return reply.status(400).send({ error: "Missing session.id" });

  const inviteId = session.inviteId ? String(session.inviteId).slice(0, 128) : null;
  const pbxCallId = session.pbxCallId ? String(session.pbxCallId).slice(0, 128) : null;
  const linkedId = session.linkedId ? String(session.linkedId).slice(0, 128) : null;
  const meta = (session.meta ?? {}) as Record<string, unknown>;
  const events = Array.isArray(session.events) ? session.events.slice(0, 200) : [];

  const startedAt = session.startedAt
    ? new Date(String(session.startedAt))
    : new Date();
  const endedAt = session.endedAt ? new Date(String(session.endedAt)) : null;

  try {
    await db.callFlightSession.upsert({
      where: { id: sessionId },
      update: {
        inviteId: inviteId ?? undefined,
        pbxCallId: pbxCallId ?? undefined,
        linkedId: linkedId ?? undefined,
        endedAt: endedAt ?? undefined,
        result: session.result ? String(session.result) : undefined,
        uiMode: session.uiMode ? String(session.uiMode) : undefined,
        events: events as any,
        hadRingtone: Boolean(stats.hadRingtone),
        hadBlankScreen: Boolean(stats.hadBlankScreen),
        hadAppRestart: Boolean(stats.hadAppRestart),
        hadFullScreen: Boolean(stats.hadFullScreen),
        answerDelayMs: typeof stats.answerDelayMs === "number" ? stats.answerDelayMs : undefined,
        sipConnectMs: typeof stats.sipConnectMs === "number" ? stats.sipConnectMs : undefined,
        pushToUiMs: typeof stats.pushToUiMs === "number" ? stats.pushToUiMs : undefined,
        warningFlags: Array.isArray(stats.warningFlags) ? stats.warningFlags.map(String) : [],
        uploadedAt: new Date(),
      },
      create: {
        id: sessionId,
        inviteId,
        pbxCallId,
        linkedId,
        tenantId: auth.tenantId || null,
        userId: auth.sub || null,
        deviceId: meta.deviceId ? String(meta.deviceId) : null,
        extension: meta.extension ? String(meta.extension) : null,
        fromNumber: meta.fromNumber ? String(meta.fromNumber) : null,
        platform: meta.platform ? String(meta.platform) : "ANDROID",
        appVersion: meta.appVersion ? String(meta.appVersion) : null,
        networkType: meta.networkType ? String(meta.networkType) : null,
        startedAt,
        endedAt,
        result: session.result ? String(session.result) : null,
        uiMode: session.uiMode ? String(session.uiMode) : null,
        events: events as any,
        hadRingtone: Boolean(stats.hadRingtone),
        hadBlankScreen: Boolean(stats.hadBlankScreen),
        hadAppRestart: Boolean(stats.hadAppRestart),
        hadFullScreen: Boolean(stats.hadFullScreen),
        answerDelayMs: typeof stats.answerDelayMs === "number" ? stats.answerDelayMs : null,
        sipConnectMs: typeof stats.sipConnectMs === "number" ? stats.sipConnectMs : null,
        pushToUiMs: typeof stats.pushToUiMs === "number" ? stats.pushToUiMs : null,
        warningFlags: Array.isArray(stats.warningFlags) ? stats.warningFlags.map(String) : [],
      },
    });
    return reply.send({ ok: true });
  } catch (e) {
    // DB may not have the table yet (migration pending) — fail silently
    console.error("[FLIGHT_RECORDER] upload failed:", (e as Error)?.message);
    return reply.send({ ok: false, note: "stored_locally" });
  }
});

// ── Admin list/search: GET /admin/call-flight/sessions ───────────────────────
app.get("/admin/call-flight/sessions", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const q = req.query as Record<string, string>;
  const inviteId = q.inviteId || null;
  const pbxCallId = q.pbxCallId || null;
  const userId = q.userId || null;
  const tenantId = q.tenantId || null;
  const result = q.result || null;
  const searchTerm = q.q || null;
  const limit = Math.min(parseInt(q.limit || "50", 10), 200);
  const offset = parseInt(q.offset || "0", 10);

  const where: Record<string, unknown> = {};
  if (inviteId) where.inviteId = inviteId;
  if (pbxCallId) where.pbxCallId = pbxCallId;
  if (userId) where.userId = userId;
  if (tenantId) where.tenantId = tenantId;
  if (result) where.result = result;
  if (searchTerm) {
    // Loose search across inviteId, pbxCallId, fromNumber, extension, userId
    (where as any).OR = [
      { inviteId: { contains: searchTerm, mode: "insensitive" } },
      { pbxCallId: { contains: searchTerm, mode: "insensitive" } },
      { fromNumber: { contains: searchTerm } },
      { extension: { contains: searchTerm } },
      { userId: { contains: searchTerm } },
    ];
  }

  try {
    const [sessions, total] = await Promise.all([
      (db as any).callFlightSession.findMany({
        where,
        orderBy: { uploadedAt: "desc" },
        take: limit,
        skip: offset,
        select: {
          id: true,
          inviteId: true,
          pbxCallId: true,
          linkedId: true,
          tenantId: true,
          userId: true,
          extension: true,
          fromNumber: true,
          platform: true,
          appVersion: true,
          result: true,
          uiMode: true,
          startedAt: true,
          endedAt: true,
          uploadedAt: true,
          hadRingtone: true,
          hadBlankScreen: true,
          hadAppRestart: true,
          hadFullScreen: true,
          answerDelayMs: true,
          sipConnectMs: true,
          pushToUiMs: true,
          warningFlags: true,
          aiSummary: true,
        },
      }),
      (db as any).callFlightSession.count({ where }),
    ]);
    return reply.send({ sessions, total, limit, offset });
  } catch (e) {
    console.error("[FLIGHT_RECORDER] list failed:", (e as Error)?.message);
    return reply.send({ sessions: [], total: 0, limit, offset });
  }
});

// ── Admin session detail: GET /admin/call-flight/sessions/:id ────────────────
app.get("/admin/call-flight/sessions/:id", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const { id } = req.params as { id: string };

  try {
    const session = await (db as any).callFlightSession.findUnique({ where: { id } });
    if (!session) return reply.status(404).send({ error: "Session not found" });
    return reply.send({ session });
  } catch (e) {
    console.error("[FLIGHT_RECORDER] get failed:", (e as Error)?.message);
    return reply.status(500).send({ error: "Failed to load session" });
  }
});

// ── Admin AI explain: POST /admin/call-flight/sessions/:id/explain ───────────
app.post("/admin/call-flight/sessions/:id/explain", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const { id } = req.params as { id: string };

  try {
    const row = await (db as any).callFlightSession.findUnique({ where: { id } });
    if (!row) return reply.status(404).send({ error: "Session not found" });

    // Return cached AI summary if available
    if (row.aiSummary) return reply.send(row.aiSummary);

    const session = row as Record<string, unknown>;
    const events: Array<Record<string, unknown>> = Array.isArray(session.events)
      ? (session.events as Array<Record<string, unknown>>)
      : [];

    const byStage = (stage: string) => events.find(e => String(e.stage) === stage);
    const hasStage = (stage: string) => events.some(e => String(e.stage) === stage);

    const pushReceived = byStage('PUSH_RECEIVED_BG') ?? byStage('PUSH_RECEIVED_FG');
    const incomingShown = byStage('INCOMING_SCREEN_SHOWN') ?? byStage('FULL_SCREEN_INCOMING_SHOWN') ?? byStage('FLOATING_BANNER_SHOWN');
    const answerTapped = byStage('ANSWER_TAPPED');
    const sipStart = byStage('SIP_ANSWER_START');
    const sipConnected = byStage('SIP_CONNECTED') ?? byStage('CALL_CONNECTED');
    const callEnded = byStage('CALL_ENDED');
    const ringtoneStart = byStage('RINGTONE_START');
    const blankScreen = byStage('BLANK_SCREEN_DETECTED');
    const appRestart = byStage('APP_REMOUNT_DETECTED') ?? byStage('SPLASH_SHOWN_AFTER_CALL');

    const result = String(session.result ?? "unknown");
    const warningFlags = Array.isArray(session.warningFlags) ? session.warningFlags : [];
    const answerDelayMs = session.answerDelayMs as number | null;
    const sipConnectMs = session.sipConnectMs as number | null;
    const pushToUiMs = session.pushToUiMs as number | null;

    function ms(a?: Record<string, unknown> | null, b?: Record<string, unknown> | null): number | null {
      if (!a?.tsMs || !b?.tsMs) return null;
      return Number(b.tsMs) - Number(a.tsMs);
    }

    function fmtMs(v: number | null): string {
      if (v === null) return "unknown";
      if (v < 1000) return `${v}ms`;
      return `${(v / 1000).toFixed(1)}s`;
    }

    // Build plain-English diagnosis
    type FlightExplain = {
      summary: string;
      whatHappened: string;
      likelyCause: string;
      suggestedFix: string;
      confidence: string;
      grade: string | null;
      warnings: string[];
      timeline: string;
    };

    function buildExplain(): FlightExplain {
      const warnings = warningFlags.map((f: unknown) => String(f));
      const timeline: string[] = [];

      if (pushReceived) timeline.push(`Push received (BG=${pushReceived.category === 'PUSH' ? 'yes' : 'no'})`);
      if (incomingShown) timeline.push(`Incoming UI shown ${pushToUiMs !== null ? `(${fmtMs(pushToUiMs)} after push)` : ""}`);
      if (ringtoneStart) timeline.push("Ringtone started");
      else if (result !== "missed" && result !== "missed_no_push") timeline.push("⚠ Ringtone did NOT start");
      if (answerTapped) timeline.push("Answer tapped");
      if (sipStart) timeline.push(`SIP answer initiated`);
      if (sipConnected) timeline.push(`SIP connected ${sipConnectMs !== null ? `(${fmtMs(sipConnectMs)} after answer)` : ""}`);
      if (callEnded) timeline.push(`Call ended`);
      if (blankScreen) timeline.push("⚠ Blank screen detected");
      if (appRestart) timeline.push("⚠ App restarted/remounted after call");

      // Result-specific explanation
      if (result === "answered" && sipConnected) {
        const grade = answerDelayMs !== null && answerDelayMs < 2000 ? "good"
          : answerDelayMs !== null && answerDelayMs < 4000 ? "fair" : "poor";
        return {
          summary: `Call answered successfully${answerDelayMs !== null ? ` in ${fmtMs(answerDelayMs)}` : ""}`,
          whatHappened: `Push was received, incoming UI appeared, the user tapped Answer, and SIP connected${sipConnectMs !== null ? ` in ${fmtMs(sipConnectMs)}` : ""}. ${warnings.length > 0 ? `Warnings: ${warnings.join(", ")}.` : ""}`,
          likelyCause: warnings.length > 0 ? `Some UX issues were detected: ${warnings.join(", ")}` : "No issues detected — normal call flow.",
          suggestedFix: warnings.includes("ANSWER_DELAY_HIGH") ? "Investigate SIP registration timing — the SIP UA may need to re-register before answering." : "None — call succeeded normally.",
          confidence: "HIGH",
          grade,
          warnings,
          timeline: timeline.join(" → "),
        };
      }

      if (result === "declined") {
        return {
          summary: "Call declined by user",
          whatHappened: "The incoming call was shown correctly. The user tapped Decline.",
          likelyCause: "User action — not an error.",
          suggestedFix: "None.",
          confidence: "HIGH",
          grade: null,
          warnings,
          timeline: timeline.join(" → "),
        };
      }

      if (result === "missed" || result === "unknown") {
        if (!incomingShown && pushReceived) {
          return {
            summary: "Push received but incoming UI never shown",
            whatHappened: "The FCM push was delivered to the device but the incoming call screen was never displayed.",
            likelyCause: "The app may not have been able to display the full-screen incoming UI. This can be caused by missing USE_FULL_SCREEN_INTENT permission on Android 14+, battery optimization killing the app, or the FCM data message arriving too late.",
            suggestedFix: "Ensure USE_FULL_SCREEN_INTENT and FOREGROUND_SERVICE_PHONE_CALL permissions are granted. Ask the user to disable battery optimization for the app.",
            confidence: "HIGH",
            grade: null,
            warnings,
            timeline: timeline.join(" → "),
          };
        }
        if (!pushReceived) {
          return {
            summary: "No push received — call missed silently",
            whatHappened: "No push received event was recorded. The call was either never pushed to this device, or the push was delivered before the app's background task could record it.",
            likelyCause: "Push delivery failure, device offline, or FCM token mismatch.",
            suggestedFix: "Check the worker CALL_TIMELINE logs for PUSH_SEND to this device. Verify the device has a valid FCM push token registered.",
            confidence: "MEDIUM",
            grade: null,
            warnings,
            timeline: timeline.join(" → "),
          };
        }
      }

      if (!sipConnected && answerTapped) {
        return {
          summary: "Call answered but SIP did not connect",
          whatHappened: `Answer was tapped but SIP ${sipStart ? "answer was initiated yet" : "answer was never started"} and never reached the connected state.${warnings.includes("SIP_REGISTER_FAILED") ? " SIP registration failed." : ""}`,
          likelyCause: warnings.includes("SIP_REGISTER_FAILED")
            ? "SIP registration failed when attempting to answer. This may indicate the SIP provisioning bundle is missing or the SIP domain is unreachable."
            : "SIP answer timed out or failed. The SIP session may have ended before the 200 OK was sent.",
          suggestedFix: "Check SIP registration logs. Ensure the SIP WS URL is reachable and credentials are valid. Look for SIP 4xx/5xx error codes in the timeline.",
          confidence: "HIGH",
          grade: "poor",
          warnings,
          timeline: timeline.join(" → "),
        };
      }

      return {
        summary: `Call ended with result: ${result}`,
        whatHappened: `${events.length} events were recorded. ${warnings.length > 0 ? `Warnings: ${warnings.join(", ")}.` : "No warnings detected."}`,
        likelyCause: "Review the full event timeline for details.",
        suggestedFix: "Check the event timeline for missing stages.",
        confidence: "LOW",
        grade: null,
        warnings,
        timeline: timeline.join(" → "),
      };
    }

    const explanation = buildExplain();

    // Cache the AI summary
    try {
      await (db as any).callFlightSession.update({
        where: { id },
        data: { aiSummary: explanation as any },
      });
    } catch {
      // Non-fatal
    }

    return reply.send(explanation);
  } catch (e) {
    console.error("[FLIGHT_RECORDER] explain failed:", (e as Error)?.message);
    return reply.status(500).send({ error: "Failed to generate explanation" });
  }
});

// ── Admin: GET /admin/call-flight/stats ───────────────────────────────────────
app.get("/admin/call-flight/stats", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const q = req.query as Record<string, string>;
  const tenantId = q.tenantId || null;
  const since = q.since ? new Date(q.since) : new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

  try {
    const where: Record<string, unknown> = { uploadedAt: { gte: since } };
    if (tenantId) where.tenantId = tenantId;

    const [total, answered, failed, missed, withWarnings, withBlank, withRestart] = await Promise.all([
      (db as any).callFlightSession.count({ where }),
      (db as any).callFlightSession.count({ where: { ...where, result: "answered" } }),
      (db as any).callFlightSession.count({ where: { ...where, result: "failed" } }),
      (db as any).callFlightSession.count({ where: { ...where, result: "missed" } }),
      (db as any).callFlightSession.count({ where: { ...where, warningFlags: { isEmpty: false } } }),
      (db as any).callFlightSession.count({ where: { ...where, hadBlankScreen: true } }),
      (db as any).callFlightSession.count({ where: { ...where, hadAppRestart: true } }),
    ]);

    return reply.send({ total, answered, failed, missed, withWarnings, withBlank, withRestart, since: since.toISOString() });
  } catch (e) {
    console.error("[FLIGHT_RECORDER] stats failed:", (e as Error)?.message);
    return reply.send({ total: 0, answered: 0, failed: 0, missed: 0, withWarnings: 0, withBlank: 0, withRestart: 0, since: since.toISOString() });
  }
});

// ── Incident Center ──────────────────────────────────────────────────────────
// Detects and surfaces platform issues in plain English for non-technical operators.
// ── Healing log proxy (admin-only, from telephony service) ────────────────────
app.get("/admin/healing/log", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  try {
    const telephonyBase = process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003";
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), 2000);
    const res = await fetch(`${telephonyBase}/healing/log?maxAgeMs=${24 * 60 * 60 * 1000}`, { signal: ctrl.signal }).finally(() => clearTimeout(t));
    if (res.ok) return reply.send(await res.json());
    return reply.send([]);
  } catch { return reply.send([]); }
});

app.get("/admin/telephony/live-diagnostics", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const query = z.object({ tenantId: z.string().optional() }).parse(req.query || {});
  const tenantId = query.tenantId?.trim() || null;
  const telephonyBase = (process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003").replace(/\/$/, "");
  const secret = String(process.env.CDR_INGEST_SECRET || "").trim();

  async function tfetch<T>(path: string, ms = 3000): Promise<T | null> {
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), ms);
    const headers: Record<string, string> = {};
    if (secret) headers["x-cdr-secret"] = secret;
    try {
      const res = await fetch(`${telephonyBase}${path}`, { headers, signal: ctrl.signal });
      return res.ok ? (await res.json() as T) : null;
    } catch {
      return null;
    } finally {
      clearTimeout(t);
    }
  }

  type DiagCall = {
    id: string;
    linkedId: string;
    state: string;
    tenantId: string | null;
    tenantName?: string | null;
    from?: string | null;
    to?: string | null;
    channels?: string[];
    isActive?: boolean;
  };
  type TelephonyDiag = {
    timestamp?: string;
    activeCallCount?: number;
    unresolvedTenantCount?: number;
    calls?: DiagCall[];
  };
  type TelephonyExtension = {
    extension: string;
    status: string;
    tenantId: string | null;
    hint?: string;
    updatedAt?: string;
  };

  const [diag, liveExtensions, dbExtensions] = await Promise.all([
    tfetch<TelephonyDiag>("/telephony/diag"),
    tfetch<TelephonyExtension[]>("/telephony/extensions"),
    db.extension.findMany({
      where: tenantId ? { tenantId, status: "ACTIVE" } : { status: "ACTIVE" },
      select: { tenantId: true, extNumber: true, displayName: true },
      orderBy: [{ tenantId: "asc" }, { extNumber: "asc" }],
      take: 1000,
    }),
  ]);

  const extensionTenantByExt = new Map<string, Set<string>>();
  for (const row of dbExtensions) {
    const set = extensionTenantByExt.get(row.extNumber) ?? new Set<string>();
    set.add(row.tenantId);
    extensionTenantByExt.set(row.extNumber, set);
  }

  const extractExtensions = (call: DiagCall): string[] => {
    const values = [
      ...(Array.isArray(call.channels) ? call.channels : []),
      call.from ?? "",
      call.to ?? "",
    ].join(" ");
    return [...new Set((values.match(/\b\d{3}\b/g) ?? []))];
  };
  const activeCalls = (diag?.calls ?? []).filter((call) => call.isActive !== false && !["hungup", "unknown"].includes(String(call.state).toLowerCase()));
  const callMatchesTenant = (call: DiagCall): boolean => {
    if (!tenantId) return true;
    if (call.tenantId === tenantId) return true;
    if (call.tenantId && call.tenantId !== tenantId) return false;
    return extractExtensions(call).some((ext) => extensionTenantByExt.get(ext)?.has(tenantId));
  };
  const scopedCalls = activeCalls.filter(callMatchesTenant);
  const scopedCallExts = new Set(scopedCalls.flatMap(extractExtensions));
  const busyStatuses = new Set(["inuse", "busy", "ringing", "onhold"]);
  const scopedLiveExtensions = (liveExtensions ?? []).filter((ext) => !tenantId || !ext.tenantId || ext.tenantId === tenantId);
  const presenceOnCallExtensions = scopedLiveExtensions
    .filter((ext) => busyStatuses.has(String(ext.status).toLowerCase()))
    .map((ext) => ({ extension: ext.extension, status: ext.status, tenantId: ext.tenantId, updatedAt: ext.updatedAt ?? null }));

  const unmatchedPresenceExtensions = presenceOnCallExtensions.filter((ext) => !scopedCallExts.has(ext.extension));
  const unmatchedLiveCalls = scopedCalls
    .map((call) => ({ ...call, extensions: extractExtensions(call) }))
    .filter((call) => call.extensions.length > 0 && !call.extensions.some((ext) => presenceOnCallExtensions.some((p) => p.extension === ext)));
  const tenantMappingFailures = activeCalls
    .map((call) => ({ call, extensions: extractExtensions(call) }))
    .filter(({ call, extensions }) => !call.tenantId && !extensions.some((ext) => extensionTenantByExt.has(ext)))
    .map(({ call, extensions }) => ({ id: call.id, linkedId: call.linkedId, state: call.state, from: call.from ?? null, to: call.to ?? null, extensions }));

  return reply.send({
    tenantId,
    generatedAt: new Date().toISOString(),
    telephonyTimestamp: diag?.timestamp ?? null,
    sourceOfTruth: "telephony.callStore.getActive via /telephony/diag",
    liveCallsCount: scopedCalls.length,
    globalLiveCallsCount: activeCalls.length,
    unresolvedTenantCount: diag?.unresolvedTenantCount ?? activeCalls.filter((call) => !call.tenantId).length,
    activeCalls: scopedCalls.map((call) => ({
      id: call.id,
      linkedId: call.linkedId,
      state: call.state,
      tenantId: call.tenantId,
      tenantName: call.tenantName ?? null,
      from: call.from ?? null,
      to: call.to ?? null,
      extensions: extractExtensions(call),
    })),
    presenceOnCallExtensions,
    unmatchedPresenceExtensions,
    unmatchedLiveCalls: unmatchedLiveCalls.map((call) => ({
      id: call.id,
      linkedId: call.linkedId,
      state: call.state,
      tenantId: call.tenantId,
      from: call.from ?? null,
      to: call.to ?? null,
      extensions: call.extensions,
    })),
    tenantMappingFailures,
    extensionDirectoryCount: dbExtensions.length,
    telephonyReachable: Boolean(diag),
  });
});

/**
 * GET /admin/telephony/live-sync-diagnostics?tenantId=<id>
 *
 * Used to prove BLF/Team Directory presence and Dashboard Live Calls agree
 * for a given tenant. Compares three sources of truth in one place:
 *   - Telephony live calls (AMI call engine, filtered per tenant)
 *   - Telephony extension presence (AMI ExtensionStatus/PeerStatus)
 *   - Connect Extension directory (DB)
 *
 * Admin-only. No PBX polling — everything served from the telephony service's
 * in-memory state plus a single cached DB read.
 */
app.get("/admin/telephony/live-sync-diagnostics", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const query = z.object({ tenantId: z.string().optional() }).parse(req.query || {});
  const selectedTenantId = query.tenantId?.trim() || null;
  const telephonyBase = (process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003").replace(/\/$/, "");
  const secret = String(process.env.CDR_INGEST_SECRET || "").trim();

  async function tfetch<T>(path: string, ms = 3000): Promise<T | null> {
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), ms);
    const headers: Record<string, string> = {};
    if (secret) headers["x-cdr-secret"] = secret;
    try {
      const res = await fetch(`${telephonyBase}${path}`, { headers, signal: ctrl.signal });
      return res.ok ? (await res.json() as T) : null;
    } catch {
      return null;
    } finally {
      clearTimeout(t);
    }
  }

  type DiagCall = {
    id: string;
    linkedId: string;
    state: string;
    tenantId: string | null;
    tenantName?: string | null;
    direction?: string | null;
    from?: string | null;
    to?: string | null;
    channels?: string[];
    extensions?: string[];
    startedAt?: string | null;
    answeredAt?: string | null;
    updatedAt?: string | null;
    isActive?: boolean;
  };
  type TelephonyDiag = { calls?: DiagCall[]; activeCallCount?: number };
  type TelephonyExtension = {
    extension: string;
    status: string;
    tenantId: string | null;
    hint?: string;
    updatedAt?: string;
  };

  const [diag, liveExtensions, tenant, dbExtensions] = await Promise.all([
    tfetch<TelephonyDiag>("/telephony/diag"),
    tfetch<TelephonyExtension[]>("/telephony/extensions"),
    selectedTenantId
      ? db.tenant.findUnique({ where: { id: selectedTenantId }, select: { id: true, name: true } })
      : Promise.resolve(null),
    db.extension.findMany({
      where: { status: "ACTIVE" },
      select: { id: true, tenantId: true, extNumber: true, displayName: true },
      take: 5000,
    }),
  ]);

  // Build the extension → tenant map the same way the resolver does: drop any
  // extNumber that appears under multiple tenants (ambiguous) to avoid leaks.
  const tenantsByExt = new Map<string, Set<string>>();
  for (const row of dbExtensions) {
    const n = row.extNumber.trim();
    if (!n) continue;
    const s = tenantsByExt.get(n) ?? new Set<string>();
    s.add(row.tenantId);
    tenantsByExt.set(n, s);
  }
  const extToTenant = new Map<string, string>();
  const extIdByTenantExt = new Map<string, string>(); // `${tenantId}:${extNumber}` → extensionId
  for (const row of dbExtensions) {
    extIdByTenantExt.set(`${row.tenantId}:${row.extNumber.trim()}`, row.id);
  }
  for (const [ext, set] of tenantsByExt) {
    if (set.size === 1) extToTenant.set(ext, [...set][0]!);
  }

  const normalizeExt = (s: string | null | undefined): string | null => {
    if (!s) return null;
    let t = String(s).trim();
    if (!t) return null;
    if (/^(?:mixing|Multicast|ConfBridge|Message|AsyncGoto)\//i.test(t)) return null;
    t = t.replace(/^(?:PJSIP|SIP|IAX2?|Local)\//i, "");
    const at = t.indexOf("@");
    if (at >= 0) t = t.slice(0, at);
    t = t.replace(/-[0-9a-f]{3,}$/i, "");
    t = t.replace(/;[\d]+$/, "");
    const p = /^[A-Za-z]\d+_(\d{2,6})$/.exec(t);
    if (p) return p[1] ?? null;
    if (/^\d{2,6}$/.test(t)) return t;
    return null;
  };
  const extractCallExtensions = (call: DiagCall): string[] => {
    const out = new Set<string>();
    for (const v of call.extensions ?? []) {
      const e = normalizeExt(v);
      if (e) out.add(e);
    }
    for (const ch of call.channels ?? []) {
      const e = normalizeExt(ch);
      if (e) out.add(e);
    }
    const fromE = normalizeExt(call.from);
    if (fromE) out.add(fromE);
    const toE = normalizeExt(call.to);
    if (toE) out.add(toE);
    return [...out];
  };

  // Active calls only (match what the dashboard renders).
  const activeCalls = (diag?.calls ?? []).filter((c) => {
    const s = String(c.state || "").toLowerCase();
    if (s === "hungup" || s === "unknown") return false;
    return c.isActive !== false;
  });
  const callBelongsToTenant = (c: DiagCall): boolean => {
    if (!selectedTenantId) return true;
    if (c.tenantId === selectedTenantId) return true;
    if (c.tenantId && c.tenantId !== selectedTenantId) return false;
    // tenantId is null — match by involved extension.
    for (const ext of extractCallExtensions(c)) {
      if (extToTenant.get(ext) === selectedTenantId) return true;
    }
    return false;
  };
  const scopedCalls = activeCalls.filter(callBelongsToTenant);

  // Presence: everything the extension store knows about, scoped to tenant.
  const presenceScoped = (liveExtensions ?? []).filter((ext) => {
    if (!selectedTenantId) return true;
    if (ext.tenantId && ext.tenantId !== selectedTenantId) return false;
    // tenantId null → fall back to the directory map.
    if (!ext.tenantId) {
      const viaDir = extToTenant.get(ext.extension);
      return viaDir ? viaDir === selectedTenantId : false;
    }
    return ext.tenantId === selectedTenantId;
  });

  const onCallStatuses = new Set(["inuse", "busy", "onhold"]);
  const ringingStatuses = new Set(["ringing"]);

  const activeExtsSet = new Set<string>();
  const ringingExtsSet = new Set<string>();
  for (const c of scopedCalls) {
    const s = String(c.state || "").toLowerCase();
    const exts = extractCallExtensions(c);
    if (s === "ringing" || s === "dialing") exts.forEach((e) => ringingExtsSet.add(e));
    else if (s === "up" || s === "held") exts.forEach((e) => activeExtsSet.add(e));
  }

  const onCallPresenceList = presenceScoped.filter((ext) => onCallStatuses.has(String(ext.status).toLowerCase()));
  const ringingPresenceList = presenceScoped.filter((ext) => ringingStatuses.has(String(ext.status).toLowerCase()));

  const liveCallsOut = scopedCalls.map((c) => {
    const s = String(c.state || "").toLowerCase();
    let derived: "ringing" | "on_call" | "dialing" | "held" | "unknown" = "unknown";
    if (s === "ringing") derived = "ringing";
    else if (s === "dialing") derived = "dialing";
    else if (s === "held") derived = "held";
    else if (s === "up") derived = "on_call";
    return {
      id: c.id,
      linkedId: c.linkedId,
      tenantId: c.tenantId ?? null,
      tenantName: c.tenantName ?? (c.tenantId ? null : null),
      status: s,
      derivedStatus: derived,
      direction: c.direction ?? null,
      from: c.from ?? null,
      to: c.to ?? null,
      caller: c.from ?? null,
      callee: c.to ?? null,
      involvedExtensions: extractCallExtensions(c),
      startedAt: c.startedAt ?? null,
      updatedAt: c.updatedAt ?? c.answeredAt ?? c.startedAt ?? null,
    };
  });

  const findMatchingCallFor = (extension: string): typeof liveCallsOut[number] | null => {
    for (const lc of liveCallsOut) {
      if (lc.involvedExtensions.includes(extension)) return lc;
    }
    return null;
  };

  const describePresence = (ext: TelephonyExtension) => {
    const extId = selectedTenantId
      ? extIdByTenantExt.get(`${selectedTenantId}:${ext.extension}`) ?? null
      : null;
    const match = findMatchingCallFor(ext.extension);
    return {
      extension: ext.extension,
      extensionId: extId,
      tenantId: ext.tenantId ?? extToTenant.get(ext.extension) ?? null,
      sourceStatus: ext.status,
      updatedAt: ext.updatedAt ?? null,
      linkedId: match?.linkedId ?? null,
      matchedCallId: match?.id ?? null,
      matchReason: match ? "matched_by_extension" : null,
    };
  };

  const unmatchedPresenceOnCall = [...onCallPresenceList, ...ringingPresenceList]
    .map(describePresence)
    .filter((p) => !p.matchedCallId)
    .map((p) => ({
      ...p,
      matchReason: "no_live_call_for_extension_in_tenant",
    }));

  const unmatchedLiveCalls = liveCallsOut.filter((c) => {
    if (c.involvedExtensions.length === 0) return false;
    const anyBusyInPresence = c.involvedExtensions.some((e) =>
      [...onCallPresenceList, ...ringingPresenceList].some((p) => p.extension === e),
    );
    return !anyBusyInPresence;
  });

  const tenantMappingFailures = activeCalls
    .filter((c) => !c.tenantId)
    .map((c) => ({
      id: c.id,
      linkedId: c.linkedId,
      from: c.from ?? null,
      to: c.to ?? null,
      extensions: extractCallExtensions(c),
      reason:
        extractCallExtensions(c).some((e) => extToTenant.has(e))
          ? "extension_known_but_not_resolved_at_ingress"
          : "no_did_no_extension_no_pbx_hint",
    }));

  return reply.send({
    tenantId: selectedTenantId,
    tenantName: tenant?.name ?? null,
    generatedAt: new Date().toISOString(),
    sourceOfTruth: "telephony.callStore.getActive via /telephony/diag + /telephony/extensions",
    liveCalls: liveCallsOut,
    presenceExtensions: presenceScoped.map(describePresence),
    blfExtensions: presenceScoped
      .filter((ext) => String(ext.status).toLowerCase() !== "unknown")
      .map(describePresence),
    unmatchedPresenceOnCall,
    unmatchedLiveCalls,
    tenantMappingFailures,
    summary: {
      liveCallsCount: liveCallsOut.length,
      onCallPresenceCount: onCallPresenceList.length,
      ringingPresenceCount: ringingPresenceList.length,
      unmatchedCount: unmatchedPresenceOnCall.length + unmatchedLiveCalls.length,
      extensionDirectorySize: extToTenant.size,
      ambiguousExtensionsDropped: [...tenantsByExt.values()].filter((s) => s.size > 1).length,
      globalActiveCallCount: activeCalls.length,
    },
  });
});

// ── Ops Center — comprehensive single-call data endpoint ───────────────────────
app.get("/admin/ops-center", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const nowMs = Date.now();
  const since24h = new Date(nowMs - 24 * 60 * 60 * 1000);
  const since1h = new Date(nowMs - 60 * 60 * 1000);
  const telephonyBase = process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003";

  async function tfetch(path: string, ms = 2500) {
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), ms);
    try {
      const r = await fetch(`${telephonyBase}${path}`, { signal: ctrl.signal });
      return r.ok ? r.json() : null;
    } catch { return null; }
    finally { clearTimeout(t); }
  }

  // ── Parallel data fetching ──────────────────────────────────────────────────
  const [
    cdrRows,
    diagRows,
    tenantRows,
    turnCnt,
    telephonyHealth,
    healingLog,
  ] = await Promise.all([
    db.connectCdr.findMany({
      where: { startedAt: { gte: since24h } },
      select: { tenantId: true, direction: true, disposition: true, startedAt: true, durationSec: true, talkSec: true },
    }).catch(() => [] as { tenantId: string | null; direction: string; disposition: string; startedAt: Date; durationSec: number; talkSec: number }[]),

    db.voiceDiagEvent.findMany({
      where: { createdAt: { gte: since24h }, type: "CALL_QUALITY_REPORT" as any },
      select: { tenantId: true, createdAt: true, payload: true },
      orderBy: { createdAt: "desc" },
      take: 400,
    }).catch(() => [] as { tenantId: string; createdAt: Date; payload: unknown }[]),

    db.tenant.findMany({ select: { id: true, name: true } }).catch(() => [] as { id: string; name: string }[]),
    db.turnConfig.count().catch(() => 0),
    tfetch("/health") as Promise<null | { status: string; ami: { connected: boolean; lastEventAt: string | null; lastError: string | null }; ari: { restHealthy: boolean; lastError: string | null }; activeCalls: number; activeExtensions: number; activeQueues: number; uptimeSec: number }>,
    tfetch(`/healing/log?maxAgeMs=${24 * 60 * 60 * 1000}`) as Promise<null | Array<{ id: string; type: string; status: string; plainEnglish: string; description: string; triggeredAt: string; resolvedAt: string | null; automated: boolean }>>,
  ]);

  // ── Tenant name map ────────────────────────────────────────────────────────
  // CDR.tenantId is either a cuid (linked Connect tenant) or "vpbx:{slug}" (unlinked PBX tenant).
  // Build a map that handles both: cuid→name from DB, vpbx:slug→prettified-slug as fallback.
  const tenantMap = new Map<string, string>(tenantRows.map((t) => [t.id, t.name]));
  const resolveTenantName = (tid: string | null | undefined): string => {
    if (!tid) return "Unknown";
    if (tenantMap.has(tid)) return tenantMap.get(tid)!;
    // vpbx:{slug} format: show prettified slug as display name
    if (tid.startsWith("vpbx:")) {
      const slug = tid.slice(5).replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
      return slug || tid;
    }
    return tid;
  };

  // ── CDR processing ─────────────────────────────────────────────────────────
  // CDR dispositions are stored lowercase: "answered", "missed", "canceled", "failed", "unknown"
  type CdrRow = typeof cdrRows[number];
  const totalCdrs = cdrRows.length;
  const answeredCdrs = cdrRows.filter((r) => r.disposition === "answered").length;
  const failedCdrs = cdrRows.filter((r) => r.disposition === "failed").length;
  const missedCdrs = cdrRows.filter((r) => r.disposition === "missed").length;
  const canceledCdrs = cdrRows.filter((r) => r.disposition === "canceled").length;
  const avgDuration = totalCdrs > 0
    ? Math.round(cdrRows.filter((r) => r.talkSec > 0).reduce((s, r) => s + r.talkSec, 0) / Math.max(answeredCdrs, 1))
    : 0;

  const dirCounts = { inbound: 0, outbound: 0, internal: 0, unknown: 0 };
  for (const r of cdrRows) {
    const d = (r.direction ?? "unknown") as keyof typeof dirCounts;
    if (d in dirCounts) dirCounts[d]++;
    else dirCounts.unknown++;
  }

  // Hourly buckets for last 24h (24 buckets)
  const hourlyBuckets: { hour: string; total: number; failed: number; missed: number }[] = [];
  for (let i = 23; i >= 0; i--) {
    const bucketStart = new Date(nowMs - (i + 1) * 3600_000);
    const bucketEnd = new Date(nowMs - i * 3600_000);
    const rows = cdrRows.filter((r) => r.startedAt >= bucketStart && r.startedAt < bucketEnd);
    hourlyBuckets.push({
      hour: bucketStart.toISOString(),
      total: rows.length,
      failed: rows.filter((r) => r.disposition === "failed" || r.disposition === "canceled").length,
      missed: rows.filter((r) => r.disposition === "missed").length,
    });
  }

  // ── Diag processing ────────────────────────────────────────────────────────
  // NOTE: The WebRTC client stores the field as 'iceConnectionState' (matching the RTCPeerConnection API).
  // 'iceState' was the incorrect field name used in early dev; it is always null.
  type DiagPayload = {
    qualityGrade?: string;
    iceConnectionState?: string; // correct field — maps to RTCPeerConnection.iceConnectionState
    isUsingRelay?: boolean;
    rttMs?: number | null;
    jitterMs?: number | null;
    packetsLost?: number;
    candidateType?: string;
    rca?: { primaryCause?: string; confidence?: number; suggestedAction?: string };
  };

  const diagPayloads = diagRows.map((d) => ({ tenantId: d.tenantId, createdAt: d.createdAt, p: (d.payload ?? {}) as DiagPayload }));
  const iceFailures = diagPayloads.filter((d) => d.p.iceConnectionState === "failed").length;
  const relayCount = diagPayloads.filter((d) => d.p.isUsingRelay === true).length;
  const directCount = diagPayloads.filter((d) => d.p.isUsingRelay === false).length;
  const poorQuality = diagPayloads.filter((d) => {
    const g = (d.p.qualityGrade ?? "").toLowerCase();
    return g === "poor" || g === "fair";
  }).length;
  const gradeCounts = { excellent: 0, good: 0, fair: 0, poor: 0 };
  for (const d of diagPayloads) {
    const g = (d.p.qualityGrade ?? "").toLowerCase() as keyof typeof gradeCounts;
    if (g in gradeCounts) gradeCounts[g]++;
  }
  const rtts = diagPayloads.map((d) => d.p.rttMs).filter((v): v is number => typeof v === "number" && v > 0);
  const jitters = diagPayloads.map((d) => d.p.jitterMs).filter((v): v is number => typeof v === "number" && v > 0);
  const avgRtt = rtts.length ? Math.round(rtts.reduce((s, v) => s + v, 0) / rtts.length) : null;
  const avgJitter = jitters.length ? Math.round(jitters.reduce((s, v) => s + v, 0) / jitters.length) : null;

  // ICE failures per hour (last 24 buckets)
  const icePerHour: { hour: string; count: number }[] = [];
  for (let i = 23; i >= 0; i--) {
    const bStart = new Date(nowMs - (i + 1) * 3600_000);
    const bEnd = new Date(nowMs - i * 3600_000);
    icePerHour.push({
      hour: bStart.toISOString(),
      count: diagPayloads.filter((d) => d.p.iceConnectionState === "failed" && d.createdAt >= bStart && d.createdAt < bEnd).length,
    });
  }

  // ── Tenant health ──────────────────────────────────────────────────────────
  type TenantHealthRow = {
    tenantId: string; tenantName: string; status: "good" | "warning" | "critical";
    activeCalls: number; failedCalls: number; missedCalls: number; totalCalls: number;
    audioIssues: number; lastIncident: string | null;
  };

  const tenantCdrMap = new Map<string, CdrRow[]>();
  for (const r of cdrRows) {
    const tid = r.tenantId ?? "unknown";
    if (!tenantCdrMap.has(tid)) tenantCdrMap.set(tid, []);
    tenantCdrMap.get(tid)!.push(r);
  }
  const tenantDiagMap = new Map<string, DiagPayload[]>();
  for (const d of diagPayloads) {
    if (!tenantDiagMap.has(d.tenantId)) tenantDiagMap.set(d.tenantId, []);
    tenantDiagMap.get(d.tenantId)!.push(d.p);
  }

  const allTenantIds = new Set([...tenantCdrMap.keys(), ...tenantDiagMap.keys()].filter((t) => t !== "unknown"));
  const tenantHealth: TenantHealthRow[] = [];
  for (const tid of allTenantIds) {
    const cdrs = tenantCdrMap.get(tid) ?? [];
    const diags = tenantDiagMap.get(tid) ?? [];
    const failed = cdrs.filter((r) => r.disposition === "failed").length;
    const canceled = cdrs.filter((r) => r.disposition === "canceled").length;
    const missed = cdrs.filter((r) => r.disposition === "missed").length;
    const audioIssues = diags.filter((d) => (d.iceConnectionState === "failed") || (d.qualityGrade ?? "").toLowerCase() === "poor").length;
    const failureRate = cdrs.length > 0 ? (failed + canceled) / cdrs.length : 0;
    let status: "good" | "warning" | "critical" = "good";
    if (failureRate > 0.2 || audioIssues > 3) status = "critical";
    else if (failureRate > 0.08 || audioIssues > 0 || missed > 3) status = "warning";
    const lastCdr = cdrs.sort((a, b) => b.startedAt.getTime() - a.startedAt.getTime())[0];
    tenantHealth.push({
      tenantId: tid,
      tenantName: resolveTenantName(tid),
      status,
      activeCalls: 0, // will be enriched from telephony if possible
      failedCalls: failed,
      missedCalls: missed,
      totalCalls: cdrs.length,
      audioIssues,
      lastIncident: (failed > 0 || audioIssues > 0) ? (lastCdr?.startedAt.toISOString() ?? null) : null,
    });
  }
  tenantHealth.sort((a, b) => {
    const sev = { critical: 3, warning: 2, good: 1 };
    return (sev[b.status] - sev[a.status]) || (b.failedCalls + b.audioIssues) - (a.failedCalls + a.audioIssues);
  });

  // ── Global health ──────────────────────────────────────────────────────────
  const dbOk = tenantRows.length >= 0; // If we got here, DB is ok
  const apiOk = true;
  const amiOk = telephonyHealth?.ami?.connected ?? false;
  const ariOk = telephonyHealth?.ari?.restHealthy ?? false;
  const pbxOk = telephonyHealth?.status === "ok";
  const turnOk = turnCnt > 0;
  const iceFailureRate = diagPayloads.length > 0 ? iceFailures / diagPayloads.length : 0;
  const webrtcStatus = iceFailureRate > 0.2 ? "critical" : iceFailureRate > 0.05 ? "warning" : "ok";

  const globalHealth = {
    api: { status: "ok" as const, label: "Connect API", lastIncident: null },
    database: { status: (dbOk ? "ok" : "down") as "ok" | "down", label: "Database", lastIncident: null },
    pbx: {
      status: (pbxOk ? "ok" : telephonyHealth ? "degraded" : "unknown") as "ok" | "degraded" | "down" | "unknown",
      label: "PBX",
      lastIncident: telephonyHealth?.ami?.lastError ?? null,
    },
    ami: {
      status: (amiOk ? "ok" : telephonyHealth ? "down" : "unknown") as "ok" | "down" | "unknown",
      label: "AMI",
      lastIncident: telephonyHealth?.ami?.lastEventAt ?? null,
      lastError: telephonyHealth?.ami?.lastError ?? null,
    },
    ari: {
      status: (ariOk ? "ok" : telephonyHealth ? "down" : "unknown") as "ok" | "down" | "unknown",
      label: "ARI",
      lastIncident: null,
      lastError: telephonyHealth?.ari?.lastError ?? null,
    },
    sbc: { status: "unknown" as const, label: "SBC", lastIncident: null },
    turn: {
      status: (turnOk ? "ok" : "missing") as "ok" | "missing",
      label: "TURN",
      lastIncident: turnOk ? null : "No TURN server configured",
    },
    workers: { status: "ok" as const, label: "Workers", lastIncident: null },
    webrtc: {
      status: webrtcStatus as "ok" | "warning" | "critical",
      label: "WebRTC",
      lastIncident: iceFailures > 0 ? `${iceFailures} ICE failure(s) in 24h` : null,
      iceFailures24h: iceFailures,
    },
  };

  // ── Live incidents ─────────────────────────────────────────────────────────
  type OpsIncident = {
    id: string; title: string; severity: "critical" | "warning" | "info";
    tenantId: string | null; tenantName: string | null;
    affectedExtension: string | null; affectedUser: string | null;
    firstSeen: string; lastSeen: string;
    status: "active" | "recovering" | "resolved";
    healingStatus: "none" | "attempted" | "succeeded" | "failed";
    likelyCause: string; suggestedAction: string;
    callCount: number; category: string;
  };

  const incidents: OpsIncident[] = [];

  if (!amiOk && telephonyHealth) {
    incidents.push({
      id: "ami-down", title: "PBX Connection Lost", severity: "critical",
      tenantId: null, tenantName: null, affectedExtension: null, affectedUser: null,
      firstSeen: new Date().toISOString(), lastSeen: new Date().toISOString(),
      status: "active", healingStatus: "attempted",
      likelyCause: "AMI connection to PBX dropped. " + (telephonyHealth.ami?.lastError ?? ""),
      suggestedAction: "Check PBX server is running and AMI credentials are correct.",
      callCount: 0, category: "connectivity",
    });
  }

  if (!turnOk) {
    incidents.push({
      id: "turn-missing", title: "No TURN Relay Configured", severity: "warning",
      tenantId: null, tenantName: null, affectedExtension: null, affectedUser: null,
      firstSeen: new Date().toISOString(), lastSeen: new Date().toISOString(),
      status: "active", healingStatus: "none",
      likelyCause: "No TURN server is configured. Remote callers on strict NAT cannot establish audio.",
      suggestedAction: "Configure a TURN server in Voice → Settings → WebRTC.",
      callCount: iceFailures, category: "audio",
    });
  }

  if (iceFailures > 0) {
    const affectedTenantIds = [...new Set(diagPayloads.filter((d) => d.p.iceConnectionState === "failed").map((d) => d.tenantId))];
    incidents.push({
      id: "ice-failures",
      title: "Audio Connection Failures",
      severity: iceFailures > 5 ? "critical" : "warning",
      tenantId: affectedTenantIds[0] ?? null,
      tenantName: affectedTenantIds[0] ? resolveTenantName(affectedTenantIds[0]) : null,
      affectedExtension: null, affectedUser: null,
      firstSeen: since24h.toISOString(), lastSeen: new Date().toISOString(),
      status: iceFailures > 5 ? "active" : "recovering",
      healingStatus: "none",
      likelyCause: `${iceFailures} call(s) failed ICE negotiation — audio could not be established. ${!turnOk ? "No TURN server is configured." : "TURN is configured but ICE still failing — check firewall."}`,
      suggestedAction: !turnOk ? "Configure TURN server." : "Check that TURN UDP/TCP ports are open.",
      callCount: iceFailures, category: "audio",
    });
  }

  if (failedCdrs > 0 && failedCdrs / Math.max(totalCdrs, 1) > 0.08) {
    incidents.push({
      id: "call-failures",
      title: "Elevated Call Failure Rate",
      severity: failedCdrs / totalCdrs > 0.2 ? "critical" : "warning",
      tenantId: null, tenantName: null, affectedExtension: null, affectedUser: null,
      firstSeen: since24h.toISOString(), lastSeen: new Date().toISOString(),
      status: "active", healingStatus: "none",
      likelyCause: `${failedCdrs} of ${totalCdrs} calls failed today (${Math.round(failedCdrs / totalCdrs * 100)}% failure rate). Likely a trunk or routing issue.`,
      suggestedAction: "Review PBX → Trunks. Check outbound routes. Inspect recent failed CDRs.",
      callCount: failedCdrs, category: "calls",
    });
  }

  // Add healing actions as "resolved" incidents
  if (healingLog) {
    for (const action of (healingLog as any[]).filter((a: any) => a.status === "succeeded").slice(0, 3)) {
      incidents.push({
        id: `healed-${action.id}`,
        title: "Auto-Recovery Completed",
        severity: "info",
        tenantId: null, tenantName: null, affectedExtension: null, affectedUser: null,
        firstSeen: action.triggeredAt, lastSeen: action.resolvedAt ?? action.triggeredAt,
        status: "resolved", healingStatus: "succeeded",
        likelyCause: action.description,
        suggestedAction: "No action required — system recovered automatically.",
        callCount: 0, category: "system",
      });
    }
  }

  // Sort: critical first, then warning, then info
  const sevOrder = { critical: 3, warning: 2, info: 1 };
  incidents.sort((a, b) => sevOrder[b.severity] - sevOrder[a.severity]);

  // ── AI Summary ─────────────────────────────────────────────────────────────
  const criticalCount = incidents.filter((i) => i.severity === "critical").length;
  const warningCount = incidents.filter((i) => i.severity === "warning").length;
  const affectedTenantNames = [...new Set(
    incidents.map((i) => i.tenantName).filter(Boolean) as string[]
  )].slice(0, 3);

  let whatHappening: string;
  let whoAffected: string;
  let likelyCause: string;
  let recommendation: string;

  if (criticalCount === 0 && warningCount === 0) {
    whatHappening = `All systems are operating normally. ${totalCdrs} calls processed in the last 24 hours with a ${totalCdrs > 0 ? Math.round(answeredCdrs / totalCdrs * 100) : 100}% answer rate.`;
    whoAffected = "No tenants are experiencing issues.";
    likelyCause = "No issues detected.";
    recommendation = "Continue monitoring. Consider configuring a TURN server if you have remote users.";
  } else {
    const mainIssue = incidents.find((i) => i.severity === "critical") ?? incidents[0];
    whatHappening = criticalCount > 0
      ? `${criticalCount} critical issue${criticalCount > 1 ? "s" : ""} require immediate attention. ${mainIssue.title}: ${mainIssue.likelyCause.slice(0, 120)}.`
      : `${warningCount} warning${warningCount > 1 ? "s" : ""} detected. ${mainIssue.title}: ${mainIssue.likelyCause.slice(0, 120)}.`;
    whoAffected = affectedTenantNames.length > 0
      ? `${affectedTenantNames.join(", ")} — and potentially any user making calls right now.`
      : `All users may be affected. ${iceFailures > 0 ? `${iceFailures} calls experienced audio failures.` : ""} ${failedCdrs > 0 ? `${failedCdrs} calls failed to connect today.` : ""}`.trim();
    likelyCause = mainIssue.likelyCause;
    recommendation = mainIssue.suggestedAction;
  }

  // ── Incident timeline ──────────────────────────────────────────────────────
  type TimelineEvent = {
    id: string; eventType: string; description: string;
    tenantName: string | null; timestamp: string; severity: "critical" | "warning" | "info";
    automated: boolean;
  };

  const timelineEvents: TimelineEvent[] = [];

  // Recent call failures
  const recentFailed = cdrRows.filter((r) => r.disposition?.toUpperCase() === "FAILED")
    .sort((a, b) => b.startedAt.getTime() - a.startedAt.getTime()).slice(0, 10);
  for (const r of recentFailed) {
    timelineEvents.push({
      id: `cdr-fail-${r.startedAt.getTime()}`,
      eventType: "call_failed",
      description: `Call failed (${r.direction ?? "unknown"} — ${r.disposition})`,
      tenantName: r.tenantId ? resolveTenantName(r.tenantId) : null,
      timestamp: r.startedAt.toISOString(),
      severity: "warning",
      automated: false,
    });
  }

  // ICE failures
  const recentIceFail = diagPayloads.filter((d) => d.p.iceConnectionState === "failed")
    .sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()).slice(0, 5);
  for (const d of recentIceFail) {
    timelineEvents.push({
      id: `ice-${d.createdAt.getTime()}`,
      eventType: "ice_failure",
      description: "ICE negotiation failed — audio could not connect",
      tenantName: resolveTenantName(d.tenantId),
      timestamp: d.createdAt.toISOString(),
      severity: "warning",
      automated: false,
    });
  }

  // Healing actions
  if (healingLog) {
    for (const action of (healingLog as any[]).slice(0, 15)) {
      timelineEvents.push({
        id: `heal-${action.id}`,
        eventType: action.status === "succeeded" ? "healing_succeeded" : action.status === "failed" ? "healing_failed" : "healing_attempted",
        description: action.plainEnglish,
        tenantName: null,
        timestamp: action.triggeredAt,
        severity: action.status === "failed" ? "warning" : "info",
        automated: true,
      });
    }
  }

  // Sort timeline by time desc, take top 30
  timelineEvents.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  const timeline = timelineEvents.slice(0, 30);

  reply.send({
    timestamp: new Date().toISOString(),
    globalHealth,
    incidents,
    aiSummary: {
      whatHappening,
      whoAffected,
      likelyCause,
      recommendation,
      generatedAt: new Date().toISOString(),
    },
    callAnalytics: {
      activeCalls: telephonyHealth?.activeCalls ?? 0,
      totalToday: totalCdrs,
      answeredToday: answeredCdrs,
      failedToday: failedCdrs,
      missedToday: missedCdrs,
      canceledToday: canceledCdrs,
      avgDurationSec: avgDuration,
      failureRate: totalCdrs > 0 ? Math.round((failedCdrs + canceledCdrs) / totalCdrs * 100) : 0,
      byDirection: dirCounts,
      hourlyBuckets,
    },
    mediaAnalytics: {
      iceFailures24h: iceFailures,
      relayCount,
      directCount,
      poorQuality,
      gradeCounts,
      icePerHour,
      avgRttMs: avgRtt,
      avgJitterMs: avgJitter,
      totalReports: diagPayloads.length,
    },
    pbxSignaling: {
      amiConnected: telephonyHealth?.ami?.connected ?? false,
      ariConnected: telephonyHealth?.ari?.restHealthy ?? false,
      activeExtensions: telephonyHealth?.activeExtensions ?? 0,
      activeQueues: telephonyHealth?.activeQueues ?? 0,
      activeCalls: telephonyHealth?.activeCalls ?? 0,
      uptimeSec: telephonyHealth?.uptimeSec ?? 0,
      lastAmiEventAt: telephonyHealth?.ami?.lastEventAt ?? null,
      lastAmiError: telephonyHealth?.ami?.lastError ?? null,
    },
    security: {
      turnMissing: !turnOk,
      iceFailures24h: iceFailures,
      note: "For detailed security metrics (login failures, rate limits), visit the Security & Abuse Grafana dashboard.",
    },
    tenantHealth: tenantHealth.slice(0, 30),
    timeline,
    healingLog: (healingLog ?? []) as any[],
    meta: {
      totalTenants: allTenantIds.size,
      dbOk,
      telephonyReachable: !!telephonyHealth,
    },
  });
});

app.get("/admin/incidents", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  const now = Date.now();
  const since2h = new Date(now - 2 * 60 * 60 * 1000);
  const since24h = new Date(now - 24 * 60 * 60 * 1000);

  // ── 1. Fetch system health from telephony service ─────────────────────────
  type TelephonyHealthResp = {
    status: "ok" | "degraded" | "down";
    ami: { connected: boolean; lastEventAt: string | null; lastError: string | null };
    ari: { restHealthy: boolean; lastError: string | null };
    activeCalls: number;
    uptimeSec: number;
  };

  let telephonyHealth: TelephonyHealthResp | null = null;
  let telephonyError: string | null = null;
  try {
    const telephonyBase = process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003";
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), 3000);
    const res = await fetch(`${telephonyBase}/health`, { signal: ctrl.signal }).finally(() => clearTimeout(t));
    if (res.ok) telephonyHealth = await res.json() as TelephonyHealthResp;
    else telephonyError = `HTTP ${res.status}`;
  } catch (err) {
    telephonyError = (err as Error)?.name === "AbortError" ? "timeout" : String((err as Error)?.message ?? err);
  }

  // ── 2. Check TURN config ──────────────────────────────────────────────────
  const turnCount = await db.turnConfig.count().catch(() => 0);

  // ── 3. Quality issues in last 2h grouped by tenant + cause ────────────────
  const recentBadEvents = await db.voiceDiagEvent.findMany({
    where: {
      createdAt: { gte: since2h },
      type: "CALL_QUALITY_REPORT",
    },
    select: {
      id: true, tenantId: true, userId: true, createdAt: true, payload: true,
      tenant: { select: { name: true } },
      user: { select: { email: true } },
    },
    orderBy: { createdAt: "desc" },
    take: 500,
  });

  const badEvents = recentBadEvents.filter((e) => {
    const p = e.payload as Record<string, unknown>;
    const grade = String(p["qualityGrade"] ?? "");
    return grade === "poor" || grade === "failed";
  });

  // Group by tenant + root cause
  const groupMap = new Map<string, {
    tenantId: string; tenantName: string; cause: string;
    count: number; lastSeenAt: Date; userEmails: Set<string>;
    samples: Array<{ grade: string; rttMs: number | null; jitterMs: number | null; isUsingRelay: boolean }>;
  }>();

  for (const ev of badEvents) {
    const p = ev.payload as Record<string, unknown>;
    const rca = p["rca"] as Record<string, unknown> | undefined;
    const cause = String(rca?.["primaryCause"] ?? "unknown");
    const key = `${ev.tenantId}::${cause}`;
    const existing = groupMap.get(key);
    if (existing) {
      existing.count++;
      if (ev.createdAt > existing.lastSeenAt) existing.lastSeenAt = ev.createdAt;
      existing.userEmails.add((ev as any).user?.email ?? ev.userId);
      existing.samples.push({ grade: String(p["qualityGrade"] ?? ""), rttMs: typeof p["rttMs"] === "number" ? p["rttMs"] : null, jitterMs: typeof p["jitterMs"] === "number" ? p["jitterMs"] : null, isUsingRelay: p["isUsingRelay"] === true });
    } else {
      groupMap.set(key, {
        tenantId: ev.tenantId,
        tenantName: (ev as any).tenant?.name ?? ev.tenantId,
        cause,
        count: 1,
        lastSeenAt: ev.createdAt,
        userEmails: new Set([(ev as any).user?.email ?? ev.userId]),
        samples: [{ grade: String(p["qualityGrade"] ?? ""), rttMs: typeof p["rttMs"] === "number" ? p["rttMs"] : null, jitterMs: typeof p["jitterMs"] === "number" ? p["jitterMs"] : null, isUsingRelay: p["isUsingRelay"] === true }],
      });
    }
  }

  // ── 4. CDR health (from live store) ──────────────────────────────────────
  const recentCdrAttempts = await db.connectCdr.count({ where: { createdAt: { gte: new Date(now - 30 * 60 * 1000) } } }).catch(() => -1);

  // ── 5. Build incident list ────────────────────────────────────────────────
  type Incident = {
    id: string;
    severity: "critical" | "warning" | "info";
    category: "system" | "audio" | "connectivity" | "security";
    title: string;
    description: string;
    affectedTenant: string | null;
    affectedUsers: number;
    likelyCause: string;
    suggestedAction: string;
    startedAt: string;
    callCount: number;
    drillDownPath: string | null;
  };

  const incidents: Incident[] = [];

  // System health incidents
  if (!telephonyHealth || telephonyError) {
    incidents.push({
      id: "sys-telephony-down",
      severity: "critical",
      category: "system",
      title: "Telephony Service Unreachable",
      description: "The telephony service is not responding. Live call events are not being processed. New calls may not appear in the dashboard.",
      affectedTenant: null,
      affectedUsers: 0,
      likelyCause: telephonyError === "timeout" ? "The telephony container may have crashed or is starting up." : `Service error: ${telephonyError}`,
      suggestedAction: "Restart the telephony container: docker restart app-telephony-1. Check logs: docker logs app-telephony-1 --tail 50",
      startedAt: new Date().toISOString(),
      callCount: 0,
      drillDownPath: null,
    });
  } else if (telephonyHealth.status === "down" || !telephonyHealth.ami.connected) {
    incidents.push({
      id: "sys-pbx-ami-down",
      severity: "critical",
      category: "connectivity",
      title: "PBX Connection Lost",
      description: "The Connect platform has lost its connection to the PBX phone system. Live call data is unavailable. Existing calls are unaffected, but no new call events are being received.",
      affectedTenant: null,
      affectedUsers: 0,
      likelyCause: telephonyHealth.ami.lastError
        ? `AMI connection error: ${telephonyHealth.ami.lastError}`
        : "The PBX may be unreachable or the AMI credentials may have changed.",
      suggestedAction: "Check that the PBX is online and reachable. Verify AMI credentials in the telephony service configuration.",
      startedAt: new Date().toISOString(),
      callCount: 0,
      drillDownPath: null,
    });
  } else if (telephonyHealth.status === "degraded" || !telephonyHealth.ari.restHealthy) {
    incidents.push({
      id: "sys-pbx-ari-degraded",
      severity: "warning",
      category: "connectivity",
      title: "PBX REST API Unreachable",
      description: "The PBX ARI (REST API) is unreachable. Call bridging and active call polling may be affected, but live call events from AMI are still flowing.",
      affectedTenant: null,
      affectedUsers: 0,
      likelyCause: telephonyHealth.ari.lastError ?? "ARI endpoint may be disabled or the port is blocked.",
      suggestedAction: "Verify ARI is enabled on the PBX (port 8088). Check firewall rules between the Connect server and PBX.",
      startedAt: new Date().toISOString(),
      callCount: 0,
      drillDownPath: null,
    });
  }

  if (turnCount === 0) {
    const missedTurnCount = badEvents.filter((e) => {
      const p = e.payload as Record<string, unknown>;
      const rca = p["rca"] as Record<string, unknown> | undefined;
      return rca?.["primaryCause"] === "TURN_missing" || p["isUsingRelay"] === false;
    }).length;
    if (missedTurnCount > 0 || badEvents.length > 2) {
      incidents.push({
        id: "sys-turn-missing",
        severity: "warning",
        category: "audio",
        title: "No TURN Server Configured",
        description: `No TURN relay server is configured. ${missedTurnCount > 0 ? `${missedTurnCount} recent calls had audio issues likely caused by missing TURN.` : "Callers on remote networks or behind strict NAT may experience no audio or one-way audio."}`,
        affectedTenant: null,
        affectedUsers: 0,
        likelyCause: "WebRTC media requires TURN relay when the caller is behind strict NAT or a corporate firewall. Without TURN, audio fails silently.",
        suggestedAction: "Go to Settings → Voice → WebRTC and configure a TURN server. Contact your hosting provider or use a service like Twilio Network Traversal or coturn.",
        startedAt: new Date().toISOString(),
        callCount: missedTurnCount,
        drillDownPath: null,
      });
    }
  }

  // CDR gap detection
  if (recentCdrAttempts === 0) {
    incidents.push({
      id: "sys-cdr-gap",
      severity: "warning",
      category: "system",
      title: "No Call Records in Last 30 Minutes",
      description: "No completed call records have been stored in the last 30 minutes. This may mean calls are not completing, the CDR pipeline has an error, or there genuinely have been no calls.",
      affectedTenant: null,
      affectedUsers: 0,
      likelyCause: "Either no calls have occurred, or the CDR ingest pipeline between the telephony service and API is failing.",
      suggestedAction: "Check CDR stats: curl http://localhost:3003/cdr-stats. Check telephony logs for CDR ingest errors.",
      startedAt: new Date().toISOString(),
      callCount: 0,
      drillDownPath: null,
    });
  }

  // Audio quality incidents per tenant
  const CAUSE_PLAIN: Record<string, { title: string; description: (count: number, tenant: string, noTurn: boolean) => string; cause: string; action: string }> = {
    ICE_failure: {
      title: "WebRTC Audio Connection Failures",
      description: (n, t, noTurn) => `${n} call(s) failed to establish audio for ${t}. ${noTurn ? "No TURN server is configured, which is the most likely cause." : "ICE negotiation failed even with TURN — a firewall may be blocking the media path."}`,
      cause: "ICE (network traversal) negotiation failed, preventing audio from being established.",
      action: "Configure a TURN relay server. If TURN is already configured, check that UDP/TCP ports are open on the TURN server.",
    },
    TURN_missing: {
      title: "Audio Issues — No Relay Server",
      description: (n, t, _) => `${n} call(s) had poor audio quality for ${t} because no TURN relay was used. Callers on strict NAT or remote networks cannot reach the PBX directly.`,
      cause: "Calls are routing audio directly without a TURN relay. This works on local networks but fails for remote callers.",
      action: "Configure a TURN server in Voice → Settings → WebRTC.",
    },
    one_way_audio: {
      title: "One-Way Audio Reported",
      description: (n, t, _) => `${n} call(s) for ${t} had one-way audio — one party could not hear the other.`,
      cause: "The RTP audio stream is only flowing one direction. Usually caused by NAT or firewall asymmetry.",
      action: "Enable TURN relay and ensure the PBX externip/localnet configuration is correct.",
    },
    packet_loss: {
      title: "Audio Quality — High Packet Loss",
      description: (n, t, _) => `${n} call(s) for ${t} had significant packet loss, causing choppy or broken audio.`,
      cause: "Audio packets are being dropped in the network between the caller and the PBX.",
      action: "TURN relay can help stabilize the media path. Advise users on poor connections to switch to wired or stronger WiFi.",
    },
    high_jitter: {
      title: "Audio Quality — Network Jitter",
      description: (n, t, _) => `${n} call(s) for ${t} had high jitter (irregular packet timing), causing robotic or choppy audio.`,
      cause: "Network congestion or unstable WiFi/cellular causing inconsistent audio packet delivery.",
      action: "Recommend users move to a more stable network. Consider enabling TURN with TCP on port 443 as a fallback.",
    },
    high_latency: {
      title: "Audio Quality — High Latency",
      description: (n, t, _) => `${n} call(s) for ${t} had high latency (round-trip > 300ms), causing noticeable audio delay.`,
      cause: "Long network path between the caller and the PBX/TURN server. May be geographic distance or routing issue.",
      action: "Consider deploying a TURN server closer to the users' region.",
    },
    unknown: {
      title: "Audio Quality Issues (Unknown Cause)",
      description: (n, t, _) => `${n} call(s) for ${t} were reported as poor quality. The root cause could not be determined automatically.`,
      cause: "Multiple possible causes — review the call timeline for specific events.",
      action: "Use Admin → Call Timeline to drill into individual sessions.",
    },
  };

  for (const [, group] of groupMap) {
    if (group.count < 1) continue;
    const hasTurn = turnCount > 0;
    const template = CAUSE_PLAIN[group.cause] ?? CAUSE_PLAIN["unknown"];
    const severity: Incident["severity"] =
      group.cause === "ICE_failure" ? "critical" :
      group.count >= 5 ? "warning" :
      "info";

    incidents.push({
      id: `audio-${group.tenantId}-${group.cause}`,
      severity,
      category: "audio",
      title: template.title,
      description: template.description(group.count, group.tenantName, !hasTurn),
      affectedTenant: group.tenantName,
      affectedUsers: group.userEmails.size,
      likelyCause: template.cause,
      suggestedAction: template.action,
      startedAt: (() => {
        const minEvent = badEvents.filter((e) => {
          const p = e.payload as Record<string, unknown>;
          const rca = p["rca"] as Record<string, unknown> | undefined;
          return e.tenantId === group.tenantId && String(rca?.["primaryCause"] ?? "unknown") === group.cause;
        }).reduce((min, e) => e.createdAt < min ? e.createdAt : min, group.lastSeenAt);
        return minEvent.toISOString();
      })(),
      callCount: group.count,
      drillDownPath: `/admin/audio-intelligence`,
    });
  }

  // Sort: critical first, then by call count
  incidents.sort((a, b) => {
    const sev = { critical: 0, warning: 1, info: 2 };
    if (sev[a.severity] !== sev[b.severity]) return sev[a.severity] - sev[b.severity];
    return b.callCount - a.callCount;
  });

  const criticalCount = incidents.filter((i) => i.severity === "critical").length;
  const warningCount = incidents.filter((i) => i.severity === "warning").length;
  const affectedTenants = new Set(incidents.filter((i) => i.affectedTenant).map((i) => i.affectedTenant)).size;

  return {
    timestamp: new Date().toISOString(),
    health: {
      api: "ok",
      telephony: telephonyHealth?.status ?? "unknown",
      pbxAmi: telephonyHealth?.ami.connected ? "connected" : "disconnected",
      pbxAri: telephonyHealth?.ari.restHealthy ? "reachable" : "unreachable",
      activeCalls: telephonyHealth?.activeCalls ?? 0,
      turnConfigured: turnCount > 0,
      uptimeSec: telephonyHealth?.uptimeSec ?? 0,
    },
    incidents,
    summary: {
      criticalCount,
      warningCount,
      infoCount: incidents.filter((i) => i.severity === "info").length,
      affectedTenants,
      totalCalls24h: await db.connectCdr.count({ where: { createdAt: { gte: since24h } } }).catch(() => 0),
    },
  };
});

// ── Tenant health endpoint (tenant-scoped, accessible to ADMIN+) ──────────────
app.get("/voice/health", async (req, reply) => {
  const user = getUser(req);
  if (!user) return reply.status(401).send({ error: "unauthorized" });

  const tenantId = user.tenantId;
  const now = Date.now();
  const startOfDay = new Date(new Date().setHours(0, 0, 0, 0));
  const since2h = new Date(now - 2 * 60 * 60 * 1000);
  const since24h = new Date(now - 24 * 60 * 60 * 1000);

  type HealthStatus = "good" | "warning" | "critical";

  // ── CDR stats for today ────────────────────────────────────────────────────
  const [totalToday, answeredToday, missedToday, failedToday] = await Promise.all([
    db.connectCdr.count({ where: { tenantId, createdAt: { gte: startOfDay } } }).catch(() => 0),
    db.connectCdr.count({ where: { tenantId, createdAt: { gte: startOfDay }, disposition: "answered" } }).catch(() => 0),
    db.connectCdr.count({ where: { tenantId, createdAt: { gte: startOfDay }, disposition: "missed" } }).catch(() => 0),
    db.connectCdr.count({ where: { tenantId, createdAt: { gte: startOfDay }, disposition: { in: ["failed", "canceled"] } } }).catch(() => 0),
  ]);

  // ── Audio quality from VoiceDiagEvent (last 24h) ───────────────────────────
  // Quality data is stored in payload JSON, not as direct columns.
  const recentDiagRaw = await db.voiceDiagEvent.findMany({
    where: { tenantId, createdAt: { gte: since24h }, type: "CALL_QUALITY_REPORT" as any },
    select: { createdAt: true, payload: true },
    orderBy: { createdAt: "desc" },
    take: 50,
  }).catch(() => [] as { createdAt: Date; payload: unknown }[]);

  type DiagP = { qualityGrade?: string; iceConnectionState?: string; rca?: { primaryCause?: string } };
  const recentDiag = recentDiagRaw.map((d) => (d.payload ?? {}) as DiagP);

  const gradeCounts: Record<string, number> = { excellent: 0, good: 0, fair: 0, poor: 0 };
  for (const d of recentDiag) {
    const g = (d.qualityGrade ?? "").toLowerCase();
    if (g in gradeCounts) gradeCounts[g]++;
  }
  const totalGraded = Object.values(gradeCounts).reduce((a, b) => a + b, 0);
  const qualityScore = totalGraded === 0 ? 100 :
    Math.round(
      (gradeCounts.excellent * 100 + gradeCounts.good * 80 + gradeCounts.fair * 50 + gradeCounts.poor * 10) /
      totalGraded
    );
  const qualityLabel =
    qualityScore >= 85 ? "Excellent" :
    qualityScore >= 70 ? "Good" :
    qualityScore >= 50 ? "Fair" : "Poor";

  const iceFailures = recentDiag.filter((d) => d.iceConnectionState === "failed").length;
  const poorCalls = gradeCounts.poor + gradeCounts.fair;

  // ── Gather healing actions for this tenant (from telephony service) ─────────
  type HealingAction = { id: string; type: string; status: string; plainEnglish: string; triggeredAt: string };
  let healingActions: HealingAction[] = [];
  try {
    const telephonyBase = process.env.TELEPHONY_INTERNAL_URL ?? "http://telephony:3003";
    const ctrl = new AbortController();
    const t = setTimeout(() => ctrl.abort(), 2000);
    const hRes = await fetch(`${telephonyBase}/healing/log?maxAgeMs=${24 * 60 * 60 * 1000}`, { signal: ctrl.signal }).finally(() => clearTimeout(t));
    if (hRes.ok) healingActions = (await hRes.json() as HealingAction[]).slice(0, 10);
  } catch { /* non-fatal */ }

  // ── Derive health status ───────────────────────────────────────────────────
  const failureRate = totalToday > 0 ? failedToday / totalToday : 0;
  let status: HealthStatus = "good";
  let statusMessage = "All systems normal. Calls are connecting and audio is clear.";

  if (failureRate > 0.2 || iceFailures > 3) {
    status = "critical";
    statusMessage = iceFailures > 3
      ? `Audio connection failures detected (${iceFailures} ICE failures in the last 24 hours). Calls may have poor or no audio.`
      : `High call failure rate — ${Math.round(failureRate * 100)}% of today's calls failed. Check your PBX trunks.`;
  } else if (failureRate > 0.08 || poorCalls > 2 || iceFailures > 0) {
    status = "warning";
    statusMessage = iceFailures > 0
      ? `Some audio quality issues detected today (${iceFailures} audio connection problems). Most calls are working normally.`
      : `A small number of calls failed today (${failedToday} out of ${totalToday}). This may be normal.`;
  }

  // ── Build incident list ────────────────────────────────────────────────────
  type TenantIncident = {
    id: string;
    severity: "critical" | "warning" | "info";
    title: string;
    description: string;
    cause: string;
    suggestedAction: string;
    affectedCount: number;
    detectedAt: string;
    autoResolved: boolean;
  };
  const incidents: TenantIncident[] = [];

  if (iceFailures > 0) {
    incidents.push({
      id: "ice-failures",
      severity: iceFailures > 3 ? "critical" : "warning",
      title: "Audio Connection Issues",
      description: `${iceFailures} call(s) in the last 24 hours failed to establish a clear audio path. Affected users may have experienced no audio or one-way audio.`,
      cause: "The system could not establish a direct audio path between the caller and the PBX. This is usually caused by strict firewall rules or missing TURN relay configuration.",
      suggestedAction: "Check Voice Settings → WebRTC and ensure a TURN server is configured. If the issue persists, contact your network administrator.",
      affectedCount: iceFailures,
      detectedAt: recentDiagRaw.find((_, i) => recentDiag[i]?.iceConnectionState === "failed")?.createdAt.toISOString() ?? new Date().toISOString(),
      autoResolved: false,
    });
  }

  if (failedToday > 0) {
    incidents.push({
      id: "call-failures",
      severity: failureRate > 0.15 ? "critical" : "warning",
      title: "Call Failures Today",
      description: `${failedToday} out of ${totalToday} calls today ended in failure. ${failureRate > 0.15 ? "This is unusually high and needs attention." : "This is slightly above normal."}`,
      cause: "Calls failed before connecting. This could be caused by a PBX trunk being offline, an incorrectly configured dial plan, or a network issue.",
      suggestedAction: "Review the Call History page to identify affected numbers and times. Check PBX → Trunks for any offline or erroring trunks.",
      affectedCount: failedToday,
      detectedAt: startOfDay.toISOString(),
      autoResolved: false,
    });
  }

  if (poorCalls > 0 && iceFailures === 0) {
    incidents.push({
      id: "poor-quality",
      severity: poorCalls > 5 ? "warning" : "info",
      title: "Some Calls Had Poor Audio Quality",
      description: `${poorCalls} call(s) in the last 24 hours received a poor or fair audio quality rating. Affected users may have noticed choppy or unclear audio.`,
      cause: "Audio quality issues can be caused by packet loss, high network jitter, or insufficient bandwidth.",
      suggestedAction: "Ask affected users to check their internet connection. If issues are widespread, contact your internet provider.",
      affectedCount: poorCalls,
      detectedAt: since24h.toISOString(),
      autoResolved: false,
    });
  }

  for (const action of healingActions.filter((a) => a.status === "succeeded")) {
    incidents.push({
      id: `healed-${action.id}`,
      severity: "info",
      title: "System Auto-Recovery",
      description: action.plainEnglish,
      cause: "An automatic recovery action was performed by the system.",
      suggestedAction: "No action required — the system recovered automatically.",
      affectedCount: 0,
      detectedAt: action.triggeredAt,
      autoResolved: true,
    });
  }

  // ── Suggested actions ──────────────────────────────────────────────────────
  const suggestedActions: string[] = [];
  if (status === "good" && incidents.length === 0) {
    suggestedActions.push("Everything looks good. No action needed.");
  }
  if (iceFailures > 0) suggestedActions.push("Configure a TURN relay server for remote callers (Voice → Settings → WebRTC).");
  if (failureRate > 0.08) suggestedActions.push("Review failed calls in Call History to identify patterns.");
  if (poorCalls > 3) suggestedActions.push("Check internet connection quality for affected users.");

  reply.send({
    tenantId,
    status,
    statusMessage,
    callsToday: {
      total: totalToday,
      answered: answeredToday,
      missed: missedToday,
      failed: failedToday,
      failureRate: totalToday > 0 ? Math.round(failureRate * 100) : 0,
    },
    audioQuality: {
      score: qualityScore,
      label: qualityLabel,
      gradeCounts,
      issueCount: poorCalls + iceFailures,
      iceFailures,
    },
    incidents,
    healingActions: healingActions.slice(0, 5),
    suggestedActions,
    lastUpdated: new Date().toISOString(),
  });
});

app.post("/mobile/devices/register", async (req, reply) => {
  const user = getUser(req);
  const input = z.object({
    platform: z.enum(["IOS", "ANDROID"]),
    expoPushToken: z.string().min(8),
    voipPushToken: z.string().optional(),
    deviceName: z.string().max(120).optional()
  }).parse(req.body || {});

  const saved = await db.mobileDevice.upsert({
    where: { expoPushToken: input.expoPushToken },
    create: {
      tenantId: user.tenantId,
      userId: user.sub,
      platform: input.platform,
      expoPushToken: input.expoPushToken,
      voipPushToken: input.voipPushToken || null,
      deviceName: input.deviceName || null,
      lastSeenAt: new Date()
    },
    update: {
      tenantId: user.tenantId,
      userId: user.sub,
      platform: input.platform,
      voipPushToken: input.voipPushToken || null,
      deviceName: input.deviceName || null,
      lastSeenAt: new Date()
    }
  });

  // Remove any OLD device registrations for this user that have a different
  // push token. A user's phone gets a new token after each APK reinstall, so
  // old tokens pile up and cause "answered on another device" false-positives
  // (both tokens get the push, the first claim triggers an INVITE_CLAIMED
  // notification to the "other" device which is the same physical phone).
  // We keep only the registration we just upserted.
  await db.mobileDevice.deleteMany({
    where: {
      tenantId: user.tenantId,
      userId: user.sub,
      expoPushToken: { not: input.expoPushToken },
    },
  });

  await audit({ tenantId: user.tenantId, actorUserId: user.sub, action: "MOBILE_DEVICE_REGISTERED", entityType: "MobileDevice", entityId: saved.id });
  return { ok: true, id: saved.id, platform: saved.platform, lastSeenAt: saved.lastSeenAt };
});

app.post("/mobile/devices/unregister", async (req, reply) => {
  const user = getUser(req);
  const input = z.object({ expoPushToken: z.string().min(8).optional() }).parse(req.body || {});

  const out = await db.mobileDevice.deleteMany({
    where: {
      tenantId: user.tenantId,
      userId: user.sub,
      ...(input.expoPushToken ? { expoPushToken: input.expoPushToken } : {})
    }
  });
  await audit({ tenantId: user.tenantId, actorUserId: user.sub, action: "MOBILE_DEVICE_UNREGISTERED", entityType: "MobileDevice", entityId: user.sub });
  return { ok: true, removed: out.count };
});

app.get("/mobile/call-invites/pending", async (req, reply) => {
  const user = getUser(req);
  if (!checkBillingRateLimit(`call-invites-poll:${user.sub}`, 60, 60 * 1000)) {
    app.log.warn({ userId: user.sub, tenantId: user.tenantId, endpoint: "/mobile/call-invites/pending" }, "rate_limit_call_invites_poll");
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }
  await db.callInvite.updateMany({ where: { tenantId: user.tenantId, userId: user.sub, status: "PENDING", expiresAt: { lt: new Date() } }, data: { status: "EXPIRED" } });
  return db.callInvite.findMany({ where: { tenantId: user.tenantId, userId: user.sub, status: "PENDING", expiresAt: { gte: new Date() } }, orderBy: { createdAt: "desc" }, take: 20 });
});

// === MULTI-CALL ================================================================
// Returns the current user's live call stack: ACCEPTED (1, the "active") and
// HELD (0..N, the hold stack ordered by stackOrder DESC so index 0 is the
// most-recently-held). Used by the mobile + web CallSessionManager on cold
// boot / reconnect to rehydrate state rather than trusting purely client-side
// session maps which are lost across app restarts.
app.get("/mobile/call-invites/active", async (req, reply) => {
  const user = getUser(req);
  if (!checkBillingRateLimit(`call-invites-active:${user.sub}`, 120, 60 * 1000)) {
    app.log.warn({ userId: user.sub, tenantId: user.tenantId, endpoint: "/mobile/call-invites/active" }, "rate_limit_call_invites_active");
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }
  const rows = await db.callInvite.findMany({
    where: { tenantId: user.tenantId, userId: user.sub, status: { in: ["ACCEPTED", "HELD"] } },
    orderBy: [{ status: "asc" }, { stackOrder: "desc" }, { createdAt: "desc" }],
    take: 10,
  });
  const active = rows.find((r) => r.status === "ACCEPTED") ?? null;
  const held = rows.filter((r) => r.status === "HELD");
  return { active, held };
});

// Mark an ACCEPTED invite as HELD. Client-initiated (user pressed Hold, or a
// sibling call was answered). We do NOT talk to the PBX here — hold is a
// client-side SIP re-INVITE (sendonly) owned by JsSIP on the device. This
// endpoint just records the multi-call stack state so other devices / web
// / reconnect hydration see the authoritative LIFO order.
app.post("/mobile/call-invites/:id/hold", async (req, reply) => {
  const user = getUser(req);
  const { id } = req.params as { id: string };
  if (!checkBillingRateLimit(`call-invites-hold:${user.sub}`, 60, 60 * 1000)) {
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }
  const invite = await db.callInvite.findFirst({ where: { id, tenantId: user.tenantId, userId: user.sub } });
  if (!invite) return reply.status(404).send({ error: "INVITE_NOT_FOUND" });
  if (invite.status !== "ACCEPTED" && invite.status !== "HELD") {
    return reply.status(409).send({ error: "INVALID_STATE", status: invite.status });
  }
  // Top-of-stack = max(stackOrder) + 1 among the user's HELD invites.
  const top = await db.callInvite.aggregate({
    where: { userId: user.sub, tenantId: user.tenantId, status: "HELD" },
    _max: { stackOrder: true },
  });
  const nextOrder = (top._max.stackOrder ?? 0) + 1;
  const updated = await db.callInvite.update({
    where: { id: invite.id },
    data: { status: "HELD", heldAt: new Date(), stackOrder: nextOrder },
  });
  app.log.info(
    { multicall: "HOLD", inviteId: invite.id, userId: user.sub, stackOrder: nextOrder },
    "[MULTICALL_BACKEND] invite_held",
  );
  return updated;
});

// Mark a HELD invite as ACCEPTED (resume) and clear its stackOrder. The client
// is responsible for ensuring only one ACCEPTED invite exists per user at a
// time; this endpoint does not enforce that (the client's hold() on the prior
// active must happen first).
app.post("/mobile/call-invites/:id/resume", async (req, reply) => {
  const user = getUser(req);
  const { id } = req.params as { id: string };
  if (!checkBillingRateLimit(`call-invites-resume:${user.sub}`, 60, 60 * 1000)) {
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }
  const invite = await db.callInvite.findFirst({ where: { id, tenantId: user.tenantId, userId: user.sub } });
  if (!invite) return reply.status(404).send({ error: "INVITE_NOT_FOUND" });
  if (invite.status !== "HELD" && invite.status !== "ACCEPTED") {
    return reply.status(409).send({ error: "INVALID_STATE", status: invite.status });
  }
  const updated = await db.callInvite.update({
    where: { id: invite.id },
    data: { status: "ACCEPTED", resumedAt: new Date(), stackOrder: null },
  });
  app.log.info(
    { multicall: "RESUME", inviteId: invite.id, userId: user.sub },
    "[MULTICALL_BACKEND] invite_resumed",
  );
  return updated;
});
// === END MULTI-CALL ============================================================

app.post("/mobile/call-invites/:id/respond", async (req, reply) => {
  const user = getUser(req);
  if (!checkBillingRateLimit(`call-invite-respond:${user.sub}`, 20, 60 * 1000)) {
    app.log.warn({ userId: user.sub, tenantId: user.tenantId, endpoint: "/mobile/call-invites/:id/respond" }, "rate_limit_call_invite_respond");
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }
  const { id } = req.params as { id: string };
  const input = z.object({ action: z.enum(["ACCEPT", "DECLINE", "ACCEPTED", "DECLINED"]) }).parse(req.body || {});
  const action = input.action === "ACCEPT" || input.action === "ACCEPTED" ? "ACCEPT" : "DECLINE";
  const now = new Date();

  const deviceIdHeader = String(req.headers["x-mobile-device-id"] || "").trim();
  const activeDevice = deviceIdHeader
    ? await db.mobileDevice.findFirst({ where: { id: deviceIdHeader, tenantId: user.tenantId, userId: user.sub } })
    : null;

  const existing = await db.callInvite.findFirst({ where: { id, tenantId: user.tenantId, userId: user.sub } });
  if (!existing) {
    return { ok: false, code: "INVITE_ALREADY_HANDLED", status: "UNKNOWN" };
  }

  if (existing.status !== "PENDING") {
    app.log.info(
      { inviteId: existing.id, action, status: existing.status, pbxCallId: existing.pbxCallId, toExtension: existing.toExtension },
      "mobile-call-invite: respond skipped because invite is no longer pending",
    );
    return { ok: false, code: "INVITE_ALREADY_HANDLED", status: existing.status, inviteId: existing.id };
  }

  if (existing.expiresAt < now) {
    await db.callInvite.updateMany({ where: { id: existing.id, status: "PENDING" }, data: { status: "EXPIRED" } });
    return { ok: false, code: "INVITE_EXPIRED", status: "EXPIRED", inviteId: existing.id };
  }

  if (action === "ACCEPT") {
    app.log.info(
      {
        callTimeline: true,
        stage: "MOBILE_INVITE_ACCEPT_REQUEST",
        ts: new Date().toISOString(),
        inviteId: existing.id,
        tenantId: user.tenantId,
        userId: user.sub,
        toExtension: existing.toExtension,
        pbxCallId: existing.pbxCallId,
        deviceId: activeDevice?.id ?? null
      },
      "[CALL_TIMELINE] MOBILE_INVITE_ACCEPT_REQUEST"
    );
    const tenant = await db.tenant.findUnique({
      where: { id: user.tenantId },
      select: {
        turnRequiredForMobile: true,
        turnValidationStatus: true,
        turnValidatedAt: true,
        mediaReliabilityGateEnabled: true,
        mediaTestStatus: true,
        mediaTestedAt: true,
        mediaLastErrorCode: true,
        mediaLastErrorAt: true,
        mediaPolicy: true
      }
    });
    if (tenant?.turnRequiredForMobile && (tenant?.mediaPolicy || "TURN_ONLY") === "TURN_ONLY" && !isTurnRecentlyVerified(tenant)) {
      return {
        ok: false,
        code: "TURN_REQUIRED_NOT_VERIFIED",
        status: existing.status,
        inviteId: existing.id,
        turnValidationStatus: tenant.turnValidationStatus,
        turnValidatedAt: tenant.turnValidatedAt || null
      };
    }
    if (tenant?.mediaReliabilityGateEnabled && !isMediaTestRecentlyPassed(tenant)) {
      return {
        ok: false,
        code: "MEDIA_TEST_REQUIRED_NOT_PASSED",
        status: existing.status,
        inviteId: existing.id,
        mediaTestStatus: tenant.mediaTestStatus || "UNKNOWN",
        mediaTestedAt: tenant.mediaTestedAt || null,
        mediaLastErrorCode: tenant.mediaLastErrorCode || null,
        mediaLastErrorAt: tenant.mediaLastErrorAt || null
      };
    }
    const claimed = await db.$transaction(async (tx) => {
      const updated = await tx.callInvite.updateMany({
        where: { id: existing.id, tenantId: user.tenantId, userId: user.sub, status: "PENDING", expiresAt: { gte: now } },
        data: { status: "ACCEPTED", acceptedAt: now, acceptedByDeviceId: activeDevice?.id || null }
      });
      const latest = await tx.callInvite.findUnique({ where: { id: existing.id } });
      return { updated: updated.count, latest };
    });

    if (claimed.updated === 0 || !claimed.latest) {
      const latestStatus = claimed.latest?.status || "UNKNOWN";
      const code = latestStatus === "EXPIRED" ? "INVITE_EXPIRED" : "INVITE_ALREADY_HANDLED";
      app.log.info(
        { inviteId: existing.id, action, latestStatus, pbxCallId: existing.pbxCallId, toExtension: existing.toExtension },
        "mobile-call-invite: accept lost race before claim completed",
      );
      return { ok: false, code, status: latestStatus, inviteId: existing.id };
    }

    try {
      await requestTelephonyInviteRequeue({
        inviteId: existing.id,
        linkedId: existing.pbxCallId,
        exten: existing.toExtension,
      });
      app.log.info(
        { inviteId: existing.id, linkedId: existing.pbxCallId, toExtension: existing.toExtension },
        "mobile-call-invite: telephony requeue requested",
      );
    } catch (err) {
      app.log.warn(
        {
          inviteId: existing.id,
          linkedId: existing.pbxCallId,
          toExtension: existing.toExtension,
          err: err instanceof Error ? err.message : String(err),
        },
        "mobile-call-invite: telephony requeue failed",
      );
    }

    await sendPushToUserDevices({
      tenantId: user.tenantId,
      userId: user.sub,
      excludeDeviceId: activeDevice?.id || null,
      payload: {
        type: "INVITE_CLAIMED",
        inviteId: existing.id,
        tenantId: user.tenantId,
        timestamp: now.toISOString()
      }
    }).catch(() => undefined);

    await audit({ tenantId: user.tenantId, actorUserId: user.sub, action: "MOBILE_CALL_INVITE_ACCEPT", entityType: "CallInvite", entityId: existing.id });
    return { ok: true, code: "INVITE_CLAIMED_OK", status: "ACCEPTED", inviteId: existing.id, acceptedByDeviceId: activeDevice?.id || null };
  }

  const declined = await db.callInvite.updateMany({
    where: { id: existing.id, tenantId: user.tenantId, userId: user.sub, status: "PENDING", expiresAt: { gte: now } },
    data: { status: "DECLINED", declinedAt: now }
  });

  if (declined.count === 0) {
    const latest = await db.callInvite.findUnique({ where: { id: existing.id } });
    const latestStatus = latest?.status || "UNKNOWN";
    const code = latestStatus === "EXPIRED" ? "INVITE_EXPIRED" : "INVITE_ALREADY_HANDLED";
    return { ok: false, code, status: latestStatus, inviteId: existing.id };
  }

  await audit({ tenantId: user.tenantId, actorUserId: user.sub, action: "MOBILE_CALL_INVITE_DECLINE", entityType: "CallInvite", entityId: existing.id });
  return { ok: true, code: "INVITE_DECLINED_OK", status: "DECLINED", inviteId: existing.id };
});

app.get("/mobile/call-invites/:id/answer-status", async (req, reply) => {
  const user = getUser(req);
  const { id } = req.params as { id: string };

  const invite = await db.callInvite.findFirst({
    where: { id, tenantId: user.tenantId, userId: user.sub },
    select: {
      id: true,
      pbxCallId: true,
      status: true,
      toExtension: true,
    },
  });

  if (!invite) {
    return reply.status(404).send({ error: "INVITE_NOT_FOUND" });
  }

  const telephony = await requestTelephonyInviteStatus({ linkedId: invite.pbxCallId }).catch((err) => ({
    linkedId: invite.pbxCallId || null,
    exists: false,
    state: null,
    answeredAt: null,
    channels: [],
    error: err instanceof Error ? err.message : String(err),
  }));

  return {
    inviteId: invite.id,
    linkedId: invite.pbxCallId || null,
    inviteStatus: invite.status,
    extension: invite.toExtension,
    pbxAnswered: !!telephony.answeredAt,
    answeredAt: telephony.answeredAt,
    telephonyState: telephony.state,
    activeChannels: telephony.channels,
    telephonyLookupError: "error" in telephony ? telephony.error : null,
  };
});

app.post("/mobile/call-invites/test", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;

  if (!checkBillingRateLimit(`mobile-invite-test:${admin.tenantId}`, 20, 60 * 60 * 1000)) {
    return reply.status(429).send({ error: "RATE_LIMITED" });
  }

  const input = z.object({
    userId: z.string().optional(),
    userEmail: z.string().email().optional(),
    fromNumber: z.string().min(2),
    toExtension: z.string().min(1),
    expiresSec: z.number().int().min(15).max(120).default(45)
  }).parse(req.body || {});

  const target = input.userId
    ? await db.user.findFirst({ where: { id: input.userId, tenantId: admin.tenantId } })
    : await db.user.findFirst({ where: { email: input.userEmail || "", tenantId: admin.tenantId } });
  if (!target) return reply.status(404).send({ error: "TARGET_USER_NOT_FOUND" });

  const ext = await db.extension.findFirst({ where: { tenantId: admin.tenantId, ownerUserId: target.id }, orderBy: { createdAt: "asc" } });
  const tenantCfg = await db.tenant.findUnique({ where: { id: admin.tenantId } });
  const invite = await db.callInvite.create({
    data: {
      tenantId: admin.tenantId,
      userId: target.id,
      extensionId: ext?.id || null,
      fromNumber: input.fromNumber,
      fromDisplay: "Test Invite",
      toExtension: input.toExtension,
      pbxSipUsername: ext?.extNumber || null,
      sipCallTarget: ext?.extNumber && tenantCfg?.sipDomain ? `sip:${ext.extNumber}@${tenantCfg.sipDomain}` : null,
      createdByEventId: `test-${Date.now()}`,
      expiresAt: new Date(Date.now() + input.expiresSec * 1000),
      status: "PENDING"
    }
  });

  const push = await sendPushToUserDevices({
    tenantId: admin.tenantId,
    userId: target.id,
    payload: {
      type: "INCOMING_CALL",
      inviteId: invite.id,
      fromNumber: invite.fromNumber,
      fromDisplay: invite.fromDisplay,
      toExtension: invite.toExtension,
      pbxCallId: invite.pbxCallId,
      sipCallTarget: invite.sipCallTarget,
      pbxSipUsername: invite.pbxSipUsername,
      tenantId: admin.tenantId,
      timestamp: new Date().toISOString()
    }
  });

  await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "MOBILE_CALL_INVITE_CREATED", entityType: "CallInvite", entityId: invite.id });
  return { ok: true, inviteId: invite.id, expiresAt: invite.expiresAt, push };
});

app.post("/webhooks/pbx", async (req, reply) => {
  const rawBody = typeof req.body === "string"
    ? req.body
    : String(req.headers["content-type"] || "").includes("application/x-www-form-urlencoded")
      ? new URLSearchParams(req.body as any).toString()
      : JSON.stringify(req.body || {});
  const verified = verifyPbxWebhook(req, rawBody);
  if (!verified.ok) {
    app.log.warn({ reason: verified.reason, sourceIp: getRequestSourceIp(req) }, "pbx webhook verification failed");
    return reply.status(403).send({ error: "INVALID_PBX_WEBHOOK", reason: verified.reason });
  }

  const normalized = normalizeWirePbxEvent(req.body || {});
  if (!normalized.pbxCallId || (normalized.state === "RINGING" && !normalized.toExtension)) {
    return reply.status(400).send({ error: "INVALID_EVENT_PAYLOAD" });
  }

  const result = await upsertInviteFromPbxEvent(normalized, "WEBHOOK");
  let pbxEventTenantId: string | null = null;
  if (result && result.ok && "inviteId" in result && result.inviteId) {
    const inv = await db.callInvite.findUnique({ where: { id: result.inviteId }, select: { tenantId: true } });
    pbxEventTenantId = inv?.tenantId ?? null;
  }
  if (pbxEventTenantId) {
    const normalizedFrom = normalizeContactNumber(normalized.fromNumber);
    const normalizedTo = normalizeContactNumber(normalized.toExtension);
    const customer = await findCustomerByContactNumber(pbxEventTenantId, normalizedFrom || normalizedTo || null);
    await db.pbxCallEvent.create({
      data: {
        tenantId: pbxEventTenantId,
        customerId: customer?.id || null,
        pbxTenantId: normalized.pbxTenantId || null,
        eventType: normalized.eventType,
        callId: normalized.pbxCallId || null,
        fromNumber: normalized.fromNumber || null,
        toNumber: normalized.toExtension || null,
        extension: normalized.pbxExtensionId || null,
        status: normalized.state || null,
        payload: normalized as any
      }
    });
  }
  return { ok: true, eventType: normalized.eventType, state: normalized.state, result };
});

app.post("/admin/pbx/events/register", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const input = z.object({ pbxInstanceId: z.string().min(1), callbackUrl: z.string().url().optional() }).parse(req.body || {});
  const instance = await db.pbxInstance.findUnique({ where: { id: input.pbxInstanceId } });
  if (!instance) return reply.status(404).send({ error: "PBX_INSTANCE_NOT_FOUND" });

  const configuredCallbackUrl = (process.env.PBX_WEBHOOK_CALLBACK_URL || "").trim();
  const publicApiBaseUrl = (process.env.NEXT_PUBLIC_API_URL || "").trim();
  const defaultCallbackUrl = configuredCallbackUrl
    || (publicApiBaseUrl ? `${publicApiBaseUrl.replace(/\/$/, "")}/webhooks/pbx` : "https://app.connectcomunications.com/api/webhooks/pbx");
  const callbackUrl = input.callbackUrl || defaultCallbackUrl;

  const auth = decryptJson<{ token: string; secret?: string }>(instance.apiAuthEncrypted);
  const client = getWirePbxClient({ baseUrl: instance.baseUrl, token: auth.token, secret: auth.secret });
  const caps = client.capabilities();
  if (!caps.supportsWebhooks) return reply.status(400).send({ error: "PBX_WEBHOOK_NOT_SUPPORTED", capabilities: caps });

  try {
    const out = await client.registerWebhook(callbackUrl);
    const reg = await db.pbxWebhookRegistration.upsert({
      where: { pbxInstanceId: instance.id },
      create: { pbxInstanceId: instance.id, webhookId: out.webhookId, callbackUrl, status: "REGISTERED" },
      update: { webhookId: out.webhookId, callbackUrl, status: "REGISTERED", lastError: null }
    });
    await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "PBX_WEBHOOK_REGISTERED", entityType: "PbxWebhookRegistration", entityId: reg.id });
    return { ok: true, registration: reg, capabilities: caps };
  } catch (e: any) {
    await db.pbxWebhookRegistration.upsert({
      where: { pbxInstanceId: instance.id },
      create: { pbxInstanceId: instance.id, webhookId: "pending", callbackUrl, status: "ERROR", lastError: String(e?.code || e?.message || "PBX_WEBHOOK_REGISTER_FAILED") },
      update: { status: "ERROR", lastError: String(e?.code || e?.message || "PBX_WEBHOOK_REGISTER_FAILED") }
    });
    return reply.status(400).send({ error: String(e?.code || "PBX_WEBHOOK_REGISTER_FAILED") });
  }
});

app.post("/admin/pbx/events/unregister", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const input = z.object({ pbxInstanceId: z.string().min(1) }).parse(req.body || {});
  const instance = await db.pbxInstance.findUnique({ where: { id: input.pbxInstanceId } });
  if (!instance) return reply.status(404).send({ error: "PBX_INSTANCE_NOT_FOUND" });

  const reg = await db.pbxWebhookRegistration.findUnique({ where: { pbxInstanceId: instance.id } });
  if (!reg) return { ok: true, removed: false };

  const auth = decryptJson<{ token: string; secret?: string }>(instance.apiAuthEncrypted);
  const client = getWirePbxClient({ baseUrl: instance.baseUrl, token: auth.token, secret: auth.secret });
  try {
    if (reg.webhookId && reg.webhookId !== "pending") {
      await client.deleteWebhook(reg.webhookId);
    }
  } catch (e: any) {
    await db.pbxWebhookRegistration.update({ where: { id: reg.id }, data: { status: "ERROR", lastError: String(e?.code || e?.message || "PBX_WEBHOOK_DELETE_FAILED") } });
    return reply.status(400).send({ error: String(e?.code || "PBX_WEBHOOK_DELETE_FAILED") });
  }

  const updated = await db.pbxWebhookRegistration.update({ where: { id: reg.id }, data: { status: "UNREGISTERED", lastError: null } });
  await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "PBX_WEBHOOK_UNREGISTERED", entityType: "PbxWebhookRegistration", entityId: reg.id });
  return { ok: true, registration: updated };
});

app.get("/admin/pbx/events/status", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const rows = await db.pbxInstance.findMany({
    orderBy: { createdAt: "desc" },
    include: { webhookRegistration: true }
  });

  const out = rows.map((r) => {
    let capabilities: any = { supportsWebhooks: false, supportsActiveCallPolling: false, webhookSignatureMode: "TOKEN" };
    try {
      const auth = decryptJson<{ token: string; secret?: string }>(r.apiAuthEncrypted);
      capabilities = getWirePbxClient({ baseUrl: r.baseUrl, token: auth.token, secret: auth.secret }).capabilities();
    } catch {
      // keep fallback capabilities
    }

    return {
      pbxInstanceId: r.id,
      name: r.name,
      baseUrl: r.baseUrl,
      isEnabled: r.isEnabled,
      capabilities,
      registration: r.webhookRegistration
        ? {
            webhookId: r.webhookRegistration.webhookId,
            callbackUrl: r.webhookRegistration.callbackUrl,
            status: r.webhookRegistration.status,
            lastEventAt: r.webhookRegistration.lastEventAt,
            lastError: r.webhookRegistration.lastError,
            updatedAt: r.webhookRegistration.updatedAt
          }
        : null
    };
  });

  return out;
});

