// ── PUT /voice/ivr/schedule ───────────────────────────────────────────────────
app.put("/voice/ivr/schedule", async (req, reply) => {
  const user = await requirePermission(req, reply, canManageIvr);
  if (!user) return;
  const body = z.object({
    tenantId:            z.string(),
    timezone:            z.string().default("America/New_York"),
    businessHoursRules:  z.array(z.object({ day: z.number().int().min(0).max(6), open: z.string(), close: z.string() })).default([]),
    holidayDates:        z.array(z.string()).default([]),
    defaultProfileId:    z.string().nullable().optional(),
    afterHoursProfileId: z.string().nullable().optional(),
    holidayProfileId:    z.string().nullable().optional(),
    isActive:            z.boolean().default(true),
  }).safeParse(req.body || {});
  if (!body.success) return reply.code(400).send({ error: "invalid_payload", issues: body.error.issues });
  const d = body.data;
  // Same vpbx:<slug> → connect tenant resolution used by DID/MOH/profile endpoints.
  const connectTenantId = d.tenantId.startsWith("vpbx:")
    ? await resolveConnectTenantIdFromScope(d.tenantId)
    : d.tenantId;
  if (!connectTenantId) {
    return reply.code(400).send({
      error: "tenant_not_linked",
      detail: "This VitalPBX tenant has no Connect tenant link yet. Link it in Admin → PBX before saving an IVR schedule.",
    });
  }
  assertIvrTenantAccess(user, connectTenantId);
  d.tenantId = connectTenantId;

  // Tenant-isolation hardening: every referenced profile ID must belong to
  // the same tenant. Prevents a Tenant A admin from attaching Tenant B's
  // route profiles to their own schedule (which would be silently accepted
  // by the upsert and later cause confusing publish output).
  const referencedIds = [d.defaultProfileId, d.afterHoursProfileId, d.holidayProfileId]
    .filter((x): x is string => typeof x === "string" && x.length > 0);
  if (referencedIds.length > 0) {
    const profiles = await (db as any).ivrRouteProfile.findMany({
      where: { id: { in: referencedIds } },
      select: { id: true, tenantId: true },
    });
    if (profiles.length !== referencedIds.length) {
      return reply.code(400).send({ error: "profile_not_found", detail: "one or more referenced profile IDs do not exist" });
    }
    const cross = profiles.find((p: { tenantId: string }) => p.tenantId !== d.tenantId);
    if (cross) {
      return reply.code(400).send({ error: "profile_wrong_tenant", detail: "referenced profile belongs to a different tenant" });
    }
  }

  const schedule = await (db as any).ivrScheduleConfig.upsert({
    where: { tenantId: d.tenantId },
    create: {
      tenantId: d.tenantId, timezone: d.timezone,
      businessHoursRules: d.businessHoursRules, holidayDates: d.holidayDates,
      defaultProfileId: d.defaultProfileId ?? null,
      afterHoursProfileId: d.afterHoursProfileId ?? null,
      holidayProfileId: d.holidayProfileId ?? null,
      isActive: d.isActive,
    },
    update: {
      timezone: d.timezone,
      businessHoursRules: d.businessHoursRules, holidayDates: d.holidayDates,
      defaultProfileId: d.defaultProfileId ?? null,
      afterHoursProfileId: d.afterHoursProfileId ?? null,
      holidayProfileId: d.holidayProfileId ?? null,
      isActive: d.isActive,
    },
  });
  return reply.send({ schedule });
});

