// ── POST /voice/moh/publish ───────────────────────────────────────────────────
// Immediately computes effective Hold Profile and writes the MOH AstDB keys.
app.post("/voice/moh/publish", async (req, reply) => {
  const user = await requirePermission(req, reply, canManageMoh);
  if (!user) return;
  const body = z.object({ tenantId: z.string() }).safeParse(req.body || {});
  if (!body.success) return reply.code(400).send({ error: "invalid_payload" });
  const tenantId = await resolveMohTenantId(body.data.tenantId);
  if (!tenantId) return reply.code(400).send({ error: "tenant_not_linked" });
  assertMohTenantAccess(user, tenantId);
  try {
    const r = await doMohPublish(tenantId, (user as any).id ?? "unknown", "manual");
    app.log.info({ tenantId, mohClass: r.profile.vitalPbxMohClassName, mode: r.mode, slug: r.slug }, "moh: publish success");
    return reply.send({ ok: true, mohClass: r.profile.vitalPbxMohClassName, mode: r.mode, slug: r.slug, recordId: r.recordId, profile: r.profile });
  } catch (err: any) {
    const code = (err as any).statusCode;
    if (code === 409) return reply.code(409).send({ error: err.message });
    app.log.warn({ tenantId, err: err?.message }, "moh: publish failed");
    return reply.code(503).send({ error: "publish_failed", detail: err?.message });
  }
});

// ── POST /voice/moh/rollback/:publishId ──────────────────────────────────────
// Restores the AstDB state to what it was BEFORE the target publish record.
// Replays previousKeysSnapshot (full MOH key snapshot stored at publish time).
app.post("/voice/moh/rollback/:publishId", async (req, reply) => {
  const user = await requirePermission(req, reply, canManageMoh);
  if (!user) return;
  const { publishId } = req.params as { publishId: string };
  const target = await (db as any).mohPublishRecord.findUnique({ where: { id: publishId } });
  if (!target) return reply.code(404).send({ error: "publish_record_not_found" });
  assertMohTenantAccess(user, target.tenantId);

  const slug = await getMohSlugForTenant(target.tenantId);
  const prevSnapshot: Array<{ family: string; key: string; value: string }> =
    Array.isArray(target.previousKeysSnapshot) && target.previousKeysSnapshot.length > 0
      ? target.previousKeysSnapshot
      : null as any;

  // Fallback for old records without previousKeysSnapshot: restore using previousMohClass minimal keys
  let restoreKeys: Array<{ family: string; key: string; value: string }>;
  let restoredClass: string;
  if (prevSnapshot) {
    restoreKeys = prevSnapshot;
    restoredClass = prevSnapshot.find((k) => k.key === "active_moh_class")?.value ?? target.previousMohClass ?? "";
  } else if (target.previousMohClass) {
    const fam = `connect/t_${slug}`;
    restoredClass = target.previousMohClass;
    restoreKeys = [
      { family: fam, key: "active_moh_class",           value: target.previousMohClass },
      { family: fam, key: "moh_class",                  value: target.previousMohClass },
      { family: fam, key: "hold_mode",                  value: "rollback" },
      { family: fam, key: "hold_announcement_enabled",  value: "0" },
      { family: fam, key: "hold_announcement_ref",      value: "" },
      { family: fam, key: "hold_announcement_interval", value: "30" },
      { family: fam, key: "intro_announcement_ref",     value: "" },
      { family: fam, key: "hold_announce",              value: "" },
      { family: fam, key: "hold_repeat",                value: "30" },
    ];
  } else {
    return reply.code(409).send({ error: "no_previous_state_to_restore" });
  }

  // Older snapshots predate the runtime `moh_class` alias. Preserve rollback
  // semantics by restoring both aliases to the same class when only one exists.
  const activeAlias = restoreKeys.find((k) => k.key === "active_moh_class");
  const runtimeAlias = restoreKeys.find((k) => k.key === "moh_class");
  if (activeAlias && !runtimeAlias) {
    restoreKeys.push({ family: activeAlias.family, key: "moh_class", value: activeAlias.value });
  } else if (runtimeAlias && !activeAlias) {
    restoreKeys.push({ family: runtimeAlias.family, key: "active_moh_class", value: runtimeAlias.value });
  }

  const record = await (db as any).mohPublishRecord.create({
    data: {
      tenantId: target.tenantId, publishedBy: (user as any).id ?? "unknown",
      source: "rollback", previousMohClass: target.newMohClass, newMohClass: restoredClass,
      keysWritten: restoreKeys, previousKeysSnapshot: Array.isArray(target.keysWritten) ? target.keysWritten : [],
      status: "pending", isRollback: true,
    },
  });

  try {
    await publishMohToAstDb(slug, restoreKeys);
    await (db as any).mohPublishRecord.update({ where: { id: record.id }, data: { status: "success" } });
    await (db as any).mohLastPublishedState.upsert({
      where: { tenantId: target.tenantId },
      create: { tenantId: target.tenantId, mohClass: restoredClass, holdMode: "rollback" },
      update: { mohClass: restoredClass, holdMode: "rollback", publishedAt: new Date() },
    });
    return reply.send({ ok: true, restoredMohClass: restoredClass, recordId: record.id });
  } catch (err: any) {
    await (db as any).mohPublishRecord.update({ where: { id: record.id }, data: { status: "failed", error: err?.message } });
    return reply.code(503).send({ error: "rollback_failed", detail: err?.message });
  }
});

// ═══════════════════════════════════════════════════════════════════════════
// MOH ASSET UPLOADS + PBX-HOST SYNC MANIFEST
//
// Tenants upload music tracks through Connect. Each upload is stored on the
// Connect side (filesystem now, S3/R2 behind the same API later) and
// catalogued as a MohAsset row. A small bash helper on the PBX host pulls
// /voice/moh/sync-manifest on a cron and mirrors the files into
// /var/lib/asterisk/moh/<mohClassName>/, then runs `asterisk -rx "moh reload"`.
//
// Call-time impact: zero. The PBX plays MOH off its own disk. Connect serves
// manifests on a cron, not per-call.
// ═══════════════════════════════════════════════════════════════════════════

// ── POST /voice/moh/assets ───────────────────────────────────────────────────
// Multipart upload: field `file` (audio bytes) + field `meta` (JSON string
// with tenantId + name). Returns the created MohAsset row. Tenant scope and
// size are enforced server-side.
app.post("/voice/moh/assets", async (req, reply) => {
  const user = await requirePermission(req, reply, canUploadMoh);
  if (!user) return;

  if (!(req as any).isMultipart?.()) {
    return reply.code(400).send({ error: "multipart_required" });
  }
  let fileBuf: Buffer | null = null;
  let originalFilename = "asset";
  let mimeType = "application/octet-stream";
  let metaRaw = "";
  try {
    // Iterate all parts once; multipart reader cannot be rewound.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const parts = (req as any).parts();
    for await (const part of parts) {
      if (part.type === "file" && part.fieldname === "file") {
        originalFilename = String(part.filename || "asset");
        mimeType = String(part.mimetype || mimeType);
        fileBuf = await part.toBuffer();
      } else if (part.type === "field" && part.fieldname === "meta") {
        metaRaw = String(part.value || "");
      }
    }
  } catch (err: any) {
    return reply.code(400).send({ error: "multipart_parse_failed", detail: err?.message });
  }

  if (!fileBuf || fileBuf.length === 0) return reply.code(400).send({ error: "file_required" });
  const metaSchema = z.object({ tenantId: z.string().min(1), name: z.string().min(1).max(100) });
  let meta: { tenantId: string; name: string };
  try { meta = metaSchema.parse(JSON.parse(metaRaw)); }
  catch { return reply.code(400).send({ error: "invalid_meta" }); }
  // `MohAsset.tenantId` FKs to `Tenant.id`, so a `vpbx:<slug>` scope would
  // violate the constraint — resolve to the linked Connect tenant first.
  const resolvedTenantId = await resolveMohTenantId(meta.tenantId);
  if (!resolvedTenantId) {
    return reply.code(400).send({
      error: "tenant_not_linked",
      detail: "This VitalPBX tenant has no Connect tenant link yet. Link it in Admin → PBX before uploading MOH assets.",
    });
  }
  assertIvrTenantAccess(user, resolvedTenantId);

  const tenantSlug = await getIvrSlugForTenant(resolvedTenantId);
  const mohClassName = buildMohClassName(tenantSlug, meta.name);

  // Duplicate-name guard — class name is unique per tenant so overlapping
  // uploads would otherwise break the PBX (two files mapping to one class).
  const existing = await (db as any).mohAsset.findFirst({
    where: { tenantId: resolvedTenantId, mohClassName },
  });
  if (existing) return reply.code(409).send({ error: "name_already_exists", detail: mohClassName });

  // Write, hash, catalog.
  let stored: { storageKey: string; sha256: string; sizeBytes: number };
  try {
    stored = await writeMohFile({
      tenantSlug, mohClassName, originalFilename, buffer: fileBuf,
    });
  } catch (err: any) {
    return reply.code(500).send({ error: "storage_write_failed", detail: err?.message });
  }

  const asset = await (db as any).mohAsset.create({
    data: {
      tenantId: resolvedTenantId,
      tenantSlug,
      name: meta.name,
      mohClassName,
      sourceFilename: originalFilename,
      storageKey: stored.storageKey,
      contentHash: stored.sha256,
      sizeBytes: stored.sizeBytes,
      mimeType,
      status: "ready",
      createdBy: (user as any).id ?? null,
    },
  }).catch(async (err: any) => {
    // Roll back the file if the DB insert lost the race on contentHash uniqueness.
    await deleteMohFile(stored.storageKey).catch(() => void 0);
    if (String(err?.code) === "P2002") throw Object.assign(new Error("duplicate_content"), { statusCode: 409 });
    throw err;
  });

  return reply.code(201).send({ asset });
});

// ── GET /voice/moh/assets ────────────────────────────────────────────────────
app.get("/voice/moh/assets", async (req, reply) => {
  const user = await requirePermission(req, reply, canUploadMoh);
  if (!user) return;
  const q = z.object({ tenantId: z.string().optional() }).parse(req.query || {});
  const isSA = String(user.role || "").toUpperCase() === "SUPER_ADMIN";
  const rawTid = isSA ? (q.tenantId ?? user.tenantId ?? null) : (user.tenantId ?? null);
  // Resolve vpbx:<slug> scope to Connect CUID; tenant-slug filter is a
  // fallback when no link exists yet so the UI can still show rows uploaded
  // against the slug.
  let where: Record<string, unknown> = {};
  if (rawTid) {
    if (rawTid.startsWith("vpbx:")) {
      const slug = rawTid.slice(5).toLowerCase();
      const resolved = await resolveConnectTenantIdFromScope(rawTid);
      where = resolved
        ? { OR: [{ tenantId: resolved }, { tenantSlug: slug }] }
        : { tenantSlug: slug };
    } else {
      where = { tenantId: rawTid };
    }
  }
  const assets = await (db as any).mohAsset.findMany({
    where: { ...where, status: { in: ["ready", "uploading"] } },
    orderBy: [{ createdAt: "desc" }],
  });
  return reply.send({ assets });
});

// ── DELETE /voice/moh/assets/:id ─────────────────────────────────────────────
// Soft-delete the catalog row and remove the file from storage. The PBX-host
// sync helper will reconcile the class directory on its next run (files not
// in the manifest get removed locally).
app.delete("/voice/moh/assets/:id", async (req, reply) => {
  const user = await requirePermission(req, reply, canUploadMoh);
  if (!user) return;
  const { id } = req.params as { id: string };
  const asset = await (db as any).mohAsset.findUnique({ where: { id } });
  if (!asset) return reply.code(404).send({ error: "asset_not_found" });
  assertIvrTenantAccess(user, asset.tenantId);

  // Archive the row so historical publishes still resolve mohClass for audit,
  // but the sync manifest will stop advertising the file.
  await (db as any).mohAsset.update({ where: { id }, data: { status: "archived" } });
  await deleteMohFile(asset.storageKey).catch(() => void 0);
  return reply.send({ ok: true });
});

// ── GET /voice/moh/sync-manifest ─────────────────────────────────────────────
// Called by the PBX-host `connect-media-sync.sh` helper. Shared-secret auth
// (x-connect-secret header) — NOT JWT, because the helper is a machine
// account outside the normal user-session flow.
//
// Response contains signed download URLs, sha256 hashes, and target MOH
// class names so the helper can diff-sync files under
// /var/lib/asterisk/moh/<mohClassName>/ and run `moh reload` only when
// something changed.
app.get("/voice/moh/sync-manifest", async (req, reply) => {
  const expected = (process.env.MOH_SYNC_SHARED_SECRET || process.env.CDR_INGEST_SECRET || "").trim();
  const provided = String((req.headers as any)["x-connect-secret"] ?? "").trim();
  if (!expected || provided !== expected) {
    return reply.code(401).send({ error: "unauthorized" });
  }

  const assets = await (db as any).mohAsset.findMany({
    where: { status: "ready" },
    orderBy: [{ tenantSlug: "asc" }, { mohClassName: "asc" }],
  });

  const publicBase = (process.env.PUBLIC_API_URL || process.env.API_BASE_URL || `http://localhost:${process.env.PORT || 3001}`).replace(/\/+$/, "");
  // 30-minute expiry gives the helper ample headroom; if the helper runs
  // every 5 minutes and one manifest takes 25 minutes to download, the
  // remaining URLs are still valid.
  const urlExpirySec = 30 * 60;

  const files = assets.map((a: any) => {
    const ext = (a.sourceFilename || "").split(".").pop() || "";
    // Target filename on the PBX side. Extension is preserved so Asterisk can
    // pick up the file format correctly; "asset.<ext>" makes the directory
    // contents deterministic for diff-sync.
    const relPath = `${a.mohClassName}/asset${ext ? "." + ext : ""}`;
    return {
      relPath,
      mohClass: a.mohClassName,
      sha256: a.contentHash,
      sizeBytes: a.sizeBytes,
      downloadUrl: buildSignedDownloadUrl(publicBase, a.storageKey, urlExpirySec),
    };
  });

  return reply.send({
    generatedAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + urlExpirySec * 1000).toISOString(),
    files,
  });
});

// ── GET /voice/moh/download/:key ─────────────────────────────────────────────
// Signed-URL download for the PBX-host helper. No JWT — signature + expiry
// are the only auth (see mohStorage.verifySignedDownload).
app.get("/voice/moh/download/*", async (req, reply) => {
  const wildcardPath = (req.params as any)["*"] as string | undefined;
  const storageKey = decodeURIComponent(String(wildcardPath || ""));
  if (!storageKey) return reply.code(400).send({ error: "missing_key" });

  const q = req.query as { exp?: string; sig?: string };
  const verified = verifySignedDownload(storageKey, q.exp, q.sig);
  if (!verified.ok) return reply.code(401).send({ error: "bad_signature", reason: verified.reason });

  let absolutePath: string;
  try { absolutePath = resolveStoragePath(storageKey); }
  catch { return reply.code(400).send({ error: "invalid_key" }); }

  if (!fs.existsSync(absolutePath)) return reply.code(404).send({ error: "not_found" });
  const stat = await fs.promises.stat(absolutePath);
  reply.header("content-length", stat.size);
  reply.header("content-type", "application/octet-stream");
  return reply.send(fs.createReadStream(absolutePath));
});

// ────────────────────────────────────────────────────────────────────────────
// PBX MOH CLASS CATALOG — existing VitalPBX MOH classes, read-only mirror
// ----------------------------------------------------------------------------
// Populated from `ombutel.ombu_music_groups` via the super-admin
// "Auto-Sync PBX MOH classes" button. Reads from Connect DB only; the PBX
// MariaDB is hit exactly once per sync run (two indexed SELECTs) — never on
// page load, never on a schedule the UI runs.
// ----------------------------------------------------------------------------

// ── GET /voice/moh/pbx-classes ────────────────────────────────────────────────
// Feeds the Hold-Profile MOH-class dropdown. Tenant-admins are pinned to their
// own tenantId; super-admins can pass ?tenantId=... or ?tenantId=__all__.
app.get("/voice/moh/pbx-classes", async (req, reply) => {
  const user = await requirePermission(req, reply, canManageMoh);
  if (!user) return;

  const q = z.object({
    tenantId: z.string().optional(),
    activeOnly: z.string().optional(),
  }).parse(req.query || {});

  const isSA = String(user.role || "").toUpperCase() === "SUPER_ADMIN";
  const wantAll = isSA && q.tenantId === "__all__";
  const rawScope = wantAll ? null : (q.tenantId || user.tenantId || null);
  if (!wantAll && !rawScope) return reply.code(400).send({ error: "tenant_required" });
  // Accept vpbx:<slug> and resolve / fall back to tenantSlug match on the
  // mirrored PbxMohClass rows (which carry tenantSlug from the ombutel sync).
  let pbxClassWhere: Record<string, unknown> = {};
  if (!wantAll && rawScope) {
    if (rawScope.startsWith("vpbx:")) {
      const slug = rawScope.slice(5).toLowerCase();
      const resolved = await resolveConnectTenantIdFromScope(rawScope);
      pbxClassWhere = resolved
        ? { OR: [{ tenantId: resolved }, { tenantSlug: slug }, { tenantId: null, tenantSlug: null }] }
        : { OR: [{ tenantSlug: slug }, { tenantId: null, tenantSlug: null }] };
    } else {
      pbxClassWhere = { OR: [{ tenantId: rawScope }, { tenantId: null }] };
      if (!isSA && rawScope !== user.tenantId) {
        return reply.code(403).send({ error: "forbidden" });
      }
    }
  }

  const rows = await (db as any).pbxMohClass.findMany({
    where: {
      ...pbxClassWhere,
      ...((q.activeOnly ?? "1") === "0" ? {} : { isActive: true }),
    },
    orderBy: [{ name: "asc" }],
    select: {
      id: true, pbxInstanceId: true, tenantId: true, tenantSlug: true,
      pbxGroupId: true, name: true, mohClassName: true, classType: true,
      isDefault: true, fileCount: true, isActive: true, lastSeenAt: true,
    },
  });
  return reply.send({
    classes: rows.map((row: any) => ({
      ...row,
      displayName: row.name,
      runtimeClass: row.mohClassName,
    })),
  });
});

// ── POST /voice/moh/pbx-classes/auto-sync ─────────────────────────────────────
// Super-admin only. Runs the bounded ombutel MariaDB sync. No polling loop.
app.post("/voice/moh/pbx-classes/auto-sync", async (req, reply) => {
  const user = await requirePermission(req, reply, canManageMoh);
  if (!user) return;
  if (String(user.role || "").toUpperCase() !== "SUPER_ADMIN") {
    return reply.code(403).send({ error: "super_admin_required" });
  }

  const body = z.object({
    pbxInstanceId: z.string().optional(),
    deactivateMissing: z.boolean().optional(),
  }).safeParse(req.body ?? {});
  if (!body.success) return reply.code(400).send({ error: "invalid_payload", issues: body.error.issues });

  const instance = body.data.pbxInstanceId
    ? await db.pbxInstance.findUnique({ where: { id: body.data.pbxInstanceId } })
    : await db.pbxInstance.findFirst({ where: { isEnabled: true }, orderBy: { createdAt: "asc" } });
  if (!instance) {
    return reply.code(404).send({
      error: "no_pbx_instance",
      hint: "Register a PbxInstance under Admin → PBX Instances first.",
    });
  }

  const { syncMohClassesFromOmbutelMysql } = await import("./pbxOmbutelMohClassSync");
  const result = await syncMohClassesFromOmbutelMysql(
    db,
    instance.id,
    instance.ombuMysqlUrlEncrypted,
    { deactivateMissing: body.data.deactivateMissing === true },
  );

  app.log.info({ pbxInstanceId: instance.id, result }, "[MOH_CLASS_AUTO_SYNC] done");
  if (result.source === "skipped") {
    return reply.send({
      ok: false,
      skipReason: result.skipReason,
      hint: "Set PbxInstance.ombuMysqlUrlEncrypted to an encrypted MySQL URL (same one used by DID sync).",
    });
  }
  return reply.send({ ok: true, result });
});

// ── POST /internal/voicemail-notify — trigger immediate sync for one mailbox ──
// Called by the telephony service on AMI MessageWaiting events.
app.post("/internal/voicemail-notify", async (req, reply) => {
  if (!verifyCdrSecret(req)) return reply.code(403).send({ error: "forbidden" });

  const body = z.object({
    mailbox: z.string().min(1),
    context: z.string().optional().default("default"),
  }).safeParse(req.body || {});
  if (!body.success) return reply.code(400).send({ error: "invalid_payload" });

  const { mailbox } = body.data;

  // Resolve extension + tenant
  const ext = await db.extension.findFirst({
    where:   { extNumber: mailbox, status: "ACTIVE" },
    include: { pbxLink: true },
  });
  if (!ext?.pbxLink?.pbxExtensionId) {
    app.log.debug({ mailbox }, "voicemail-notify: extension not found — skipping");
    return reply.send({ ok: true, synced: false, reason: "extension_not_found" });
  }

  try {
    const link = await db.tenantPbxLink.findUnique({
      where:   { tenantId: ext.tenantId },
      include: { pbxInstance: true },
    });
    if (!link?.pbxInstance) return reply.send({ ok: true, synced: false, reason: "no_pbx_link" });

    const auth    = decryptJson<{ token: string; secret?: string }>(link.pbxInstance.apiAuthEncrypted);
    const pbx     = getVitalPbxClient({ baseUrl: link.pbxInstance.baseUrl, token: auth.token, secret: auth.secret });
    const records = await pbx.getExtensionVoicemailRecords(ext.pbxLink.pbxExtensionId, link.pbxTenantId ?? undefined);

    let upserted = 0;
    for (const rec of records) {
      // VitalPBX: { date, clid, recfile, filename, msg_id }. Legacy: { origtime, callerid, msg_num }.
      const origtime = String(rec.date ?? rec.origtime ?? rec.orig_time ?? "");
      if (!origtime || origtime === "0") continue;
      const rawCallerid  = String(rec.clid ?? rec.callerid ?? rec.caller_id ?? "");
      const callerNumber = vmExtractCallerNumber(rawCallerid) || null;
      const callerDigits = (callerNumber ?? "").slice(-10);
      const msgId        = String(
        rec.msg_id
          ?? `${link.pbxTenantId || link.tenantId}|${ext.extNumber}|${origtime}|${callerDigits}`,
      );
      const rawFolder    = String(rec.folder ?? "INBOX");
      const folder       = vmNormalizeFolder(rawFolder);
      const filename     = String(rec.filename ?? "");
      const recfile      = String(rec.recfile ?? "");
      const fromFilename = filename.replace(/\.[^.]+$/, "");
      const fromRecfile  = recfile ? (recfile.split("/").pop() ?? "").replace(/\.[^.]+$/, "") : "";
      const pbxMsgNum    = String(
        rec.msg_num ?? rec.msgnum ?? rec.id ?? fromFilename ?? fromRecfile ?? "",
      );

      await db.voicemail.upsert({
        where:  { pbxMessageId: msgId },
        create: {
          pbxMessageId:  msgId,
          tenantId:      link.tenantId,
          extension:     ext.extNumber,
          pbxExtensionId: ext.pbxLink!.pbxExtensionId,
          callerNumber,
          callerName:    vmExtractCallerName(rawCallerid) || null,
          durationSec:   parseInt(String(rec.duration ?? "0"), 10) || 0,
          folder,
          pbxFolder:     rawFolder,
          pbxMsgNum,
          pbxRecfile:    recfile || null,
          listened:      folder !== "inbox",
          receivedAt:    new Date(parseInt(origtime, 10) * 1000),
        },
        update: {
          folder,
          pbxFolder: rawFolder,
          pbxMsgNum,
          ...(recfile ? { pbxRecfile: recfile } : {}),
          callerNumber,
          callerName: vmExtractCallerName(rawCallerid) || null,
          listened: folder !== "inbox",
        },
      });
      upserted++;
    }

    app.log.info({ mailbox, upserted }, "voicemail-notify: sync complete");
    return reply.send({ ok: true, synced: true, upserted });
  } catch (err: any) {
    app.log.warn({ mailbox, err: err?.message }, "voicemail-notify: sync failed");
    return reply.code(500).send({ error: "sync_failed" });
  }
});

// ═══════════════════════════════════════════════════════════════════════════════

app.get("/calls/history", async (req, reply) => {
  const user = await requirePermission(req, reply, canViewCustomers);
  if (!user) return;

  const query = z.object({
    tenantId: z.string().optional(),
    startDate: z.string().optional(),
    endDate: z.string().optional(),
    direction: z.enum(["all", "incoming", "outgoing", "internal"]).optional().default("all"),
    status: z.enum(["all", "answered", "missed", "canceled", "failed"]).optional().default("all"),
    hasRecording: z.enum(["all", "yes", "no"]).optional().default("all"),
    search: z.string().optional(),
    page: z.coerce.number().int().min(1).optional().default(1),
    pageSize: z.coerce.number().int().min(10).max(200).optional().default(100),
  }).parse(req.query || {});

  const isSuperAdmin = String(user.role || "").toUpperCase() === "SUPER_ADMIN";
  const requestedTenantId = query.tenantId && query.tenantId !== "global" ? query.tenantId : null;

  // Build the set of tenantId values to filter by.
  // null = global / no restriction.
  // string[] = must match one of these values (handles CDRs stored in multiple formats).
  //
  // KEY INSIGHT: CDR rows are stored with tenantId = "vpbx:{slug}" (e.g. "vpbx:gesheft").
  // The old code resolved vpbx: IDs to Connect cuids, then filtered by the cuid — which
  // never matched anything because CDRs don't have cuids. Fix: use the vpbx: slug directly
  // as the filter value, and also include any resolved cuid for the rare rows that have it.
  let tenantIdFilter: string[] | null = null;

  if (!isSuperAdmin) {
    // Non-super-admins: always scoped to their own tenant cuid.
    if (user.tenantId) tenantIdFilter = [user.tenantId];
  } else if (requestedTenantId) {
    if (requestedTenantId.startsWith("vpbx:")) {
      // CDR rows use "vpbx:{slug}" as their tenantId — include it directly.
      const vpbxSlug = requestedTenantId.slice(5).trim();
      const ids: string[] = [requestedTenantId];

      // Also include the linked Connect tenant cuid (for the rare CDRs written with the real cuid).
      let link = await db.tenantPbxLink.findFirst({ where: { pbxTenantId: vpbxSlug } });
      if (!link) {
        const dir = await db.pbxTenantDirectory.findFirst({ where: { tenantSlug: vpbxSlug } });
        if (dir?.vitalTenantId) {
          link = await db.tenantPbxLink.findFirst({ where: { pbxTenantId: dir.vitalTenantId } });
        }
      }
      if (link?.tenantId) ids.push(link.tenantId);
      tenantIdFilter = ids;
    } else {
      // Real Connect cuid requested (non-vpbx tenant or regular admin).
      // Also find the vpbx: slug so CDRs stored in that format are included.
      const ids: string[] = [requestedTenantId];
      const link = await db.tenantPbxLink.findFirst({ where: { tenantId: requestedTenantId } });
      if (link?.pbxTenantId) {
        const dir = await db.pbxTenantDirectory.findFirst({ where: { vitalTenantId: link.pbxTenantId } });
        if (dir?.tenantSlug) ids.push(`vpbx:${dir.tenantSlug}`);
      }
      tenantIdFilter = ids;
    }
    app.log.info(
      { requestedTenantId, tenantIdFilter, mode: "TENANT" },
      "[CALL_HISTORY_FILTER] resolved tenant scope"
    );
  } else {
    app.log.info({ mode: "GLOBAL" }, "[CALL_HISTORY_FILTER] resolved tenant scope");
  }

  const { dayStartUtc, dayEndUtc } = computePbxLocalDayRangeUtc();
  const startAt = query.startDate ? new Date(query.startDate) : dayStartUtc;
  const endAt = query.endDate ? new Date(query.endDate) : dayEndUtc;
  if (!Number.isFinite(startAt.getTime()) || !Number.isFinite(endAt.getTime()) || startAt >= endAt) {
    return reply.status(400).send({ error: "invalid_date_window" });
  }

  const where: any = {
    startedAt: { gte: startAt, lt: endAt },
    ...(tenantIdFilter
      ? tenantIdFilter.length === 1
        ? { tenantId: tenantIdFilter[0] }
        : { tenantId: { in: tenantIdFilter } }
      : {}),
  };

  if (query.direction !== "all") where.direction = query.direction;

  if (query.status !== "all") {
    if (query.status === "answered") where.disposition = "answered";
    else if (query.status === "canceled") where.disposition = "canceled";
    else if (query.status === "failed") where.disposition = "failed";
    else if (query.status === "missed") where.disposition = { in: ["missed", "busy", "no answer", "no_answer"] };
  }

  // hasRecording filter — was parsed but previously never applied to the query.
  if (query.hasRecording === "yes") where.recordingPath = { not: null };
  else if (query.hasRecording === "no") where.recordingPath = null;

  const normalizedSearch = String(query.search || "").trim();
  if (normalizedSearch) {
    where.OR = [
      { fromNumber: { contains: normalizedSearch, mode: "insensitive" } },
      { toNumber: { contains: normalizedSearch, mode: "insensitive" } },
    ];
  }

  const skip = (query.page - 1) * query.pageSize;
  const [total, rows, incoming, outgoing, internal] = await Promise.all([
    db.connectCdr.count({ where }),
    db.connectCdr.findMany({
      where,
      orderBy: { startedAt: "desc" },
      skip,
      take: query.pageSize,
      select: {
        id: true,
        linkedId: true,
        fromNumber: true,
        fromName: true,
        toNumber: true,
        dcontext: true,
        dcontextsSeen: true,
        channelsSeen: true,
        direction: true,
        disposition: true,
        durationSec: true,
        talkSec: true,
        startedAt: true,
        answeredAt: true,
        endedAt: true,
        tenantId: true,
        pbxVitalTenantId: true,
        pbxTenantCode: true,
        tenantResolutionSource: true,
        queueId: true,
        hangupCause: true,
        recordingPath: true,
      },
    }),
    db.connectCdr.count({ where: { ...where, direction: "incoming" } }),
    db.connectCdr.count({ where: { ...where, direction: "outgoing" } }),
    db.connectCdr.count({ where: { ...where, direction: "internal" } }),
  ]);

  const extensionCandidates = Array.from(new Set(
    rows
      .flatMap((r) => [extractLikelyExtension(r.fromNumber), extractLikelyExtension(r.toNumber)])
      .filter((v): v is string => Boolean(v))
  ));
  const didCandidatesLast10 = Array.from(new Set(
    rows
      .flatMap((r) => [digitsOnly(r.fromNumber), digitsOnly(r.toNumber)])
      .map((d) => (d.length >= 10 ? d.slice(-10) : ""))
      .filter((v) => Boolean(v))
  ));
  const [extensions, pbxExtLinks, tenantRules] = await Promise.all([
    extensionCandidates.length > 0
      ? db.extension.findMany({
        where: { extNumber: { in: extensionCandidates } },
        select: { extNumber: true, tenantId: true },
      })
      : Promise.resolve([]),
    extensionCandidates.length > 0
      ? db.pbxExtensionLink.findMany({
        where: { pbxExtensionId: { in: extensionCandidates } },
        select: { pbxExtensionId: true, tenantId: true },
      })
      : Promise.resolve([]),
    db.cdrTenantRule.findMany({
      select: { matchType: true, matchValue: true, tenantSlug: true },
    }),
  ]);
  const phoneRows = didCandidatesLast10.length > 0
    ? await db.phoneNumber.findMany({
      where: {
        OR: didCandidatesLast10.map((d) => ({ phoneNumber: { endsWith: d } })),
      },
      select: { phoneNumber: true, tenantId: true },
    })
    : [];
  // Recording availability comes directly from ConnectCdr.recordingPath (deterministic,
  // set at ingest). No PBX lookup, no CallRecording table — the stream endpoint will
  // 404 on user click if the file is not actually on the PBX.
  const extensionTenantByExt = new Map<string, string>();
  for (const e of extensions) {
    if (!extensionTenantByExt.has(e.extNumber)) extensionTenantByExt.set(e.extNumber, e.tenantId);
  }
  const extensionTenantByPbxExtId = new Map<string, string>();
  for (const l of pbxExtLinks) {
    const ext = String(l.pbxExtensionId || "").trim();
    if (ext && !extensionTenantByPbxExtId.has(ext)) extensionTenantByPbxExtId.set(ext, l.tenantId);
  }
  const phoneTenantByLast10 = new Map<string, string>();
  for (const p of phoneRows) {
    const d = digitsOnly(p.phoneNumber);
    if (d.length < 10) continue;
    const last10 = d.slice(-10);
    if (!phoneTenantByLast10.has(last10)) phoneTenantByLast10.set(last10, p.tenantId);
  }
  const ombuDidTenantByLast10 = new Map<string, string>();
  if (didCandidatesLast10.length > 0) {
    const pbxHistInstance = await db.pbxInstance.findFirst({
      where: { isEnabled: true },
      orderBy: { updatedAt: "desc" },
      select: { id: true },
    });
    if (pbxHistInstance) {
      const didHits = await db.pbxTenantInboundDid.findMany({
        where: {
          pbxInstanceId: pbxHistInstance.id,
          active: true,
          e164: { in: [...new Set(didCandidatesLast10)] },
          connectTenantId: { not: null },
        },
        select: { e164: true, connectTenantId: true },
      });
      for (const h of didHits) {
        if (h.connectTenantId && !ombuDidTenantByLast10.has(h.e164)) {
          ombuDidTenantByLast10.set(h.e164, h.connectTenantId);
        }
      }
    }
  }
  // Learn ext→tenant from recent ConnectCdr rows with real tenant IDs.
  const learnedExtTenantByExt = new Map<string, string>();
  if (extensionCandidates.length > 0) {
    const extListSql = extensionCandidates.map((e) => `'${e.replace(/'/g, "''")}'`).join(", ");
    type ExtTenantRow = { ext: string; tenantId: string; c: bigint };
    const learnedExt = await db.$queryRawUnsafe<ExtTenantRow[]>(`
      WITH ext_rows AS (
        SELECT
          "tenantId",
          REGEXP_REPLACE(COALESCE("fromNumber", ''), '[^0-9]', '', 'g') AS ext
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '90 days'
        UNION ALL
        SELECT
          "tenantId",
          REGEXP_REPLACE(COALESCE("toNumber", ''), '[^0-9]', '', 'g') AS ext
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '90 days'
      ),
      ranked AS (
        SELECT
          ext,
          "tenantId",
          COUNT(*)::bigint AS c,
          ROW_NUMBER() OVER (PARTITION BY ext ORDER BY COUNT(*) DESC) AS rn
        FROM ext_rows
        WHERE LENGTH(ext) BETWEEN 2 AND 6
          AND ext IN (${extListSql})
        GROUP BY ext, "tenantId"
      )
      SELECT ext, "tenantId", c
      FROM ranked
      WHERE rn = 1
    `);
    for (const row of learnedExt) {
      if (!learnedExtTenantByExt.has(row.ext)) {
        learnedExtTenantByExt.set(row.ext, row.tenantId);
      }
    }
  }
  // Learn DID→tenant from recent ConnectCdr rows with known tenantId.
  // This helps label legacy/unassigned rows where DID inventory or explicit rules are incomplete.
  const learnedDidTenantByLast10 = new Map<string, string>();
  if (didCandidatesLast10.length > 0) {
    const didListSql = didCandidatesLast10.map((d) => `'${d.replace(/'/g, "''")}'`).join(", ");
    type DidTenantRow = { did10: string; tenantId: string; c: bigint };
    const learned = await db.$queryRawUnsafe<DidTenantRow[]>(`
      WITH normalized AS (
        SELECT
          "tenantId",
          RIGHT(REGEXP_REPLACE(COALESCE("toNumber", ''), '[^0-9]', '', 'g'), 10) AS did10
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '30 days'
        UNION ALL
        SELECT
          "tenantId",
          RIGHT(REGEXP_REPLACE(COALESCE("fromNumber", ''), '[^0-9]', '', 'g'), 10) AS did10
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '30 days'
      ),
      ranked AS (
        SELECT
          did10,
          "tenantId",
          COUNT(*)::bigint AS c,
          ROW_NUMBER() OVER (PARTITION BY did10 ORDER BY COUNT(*) DESC) AS rn
        FROM normalized
        WHERE LENGTH(did10) = 10
          AND did10 IN (${didListSql})
        GROUP BY did10, "tenantId"
      )
      SELECT did10, "tenantId", c
      FROM ranked
      WHERE rn = 1
    `);
    for (const row of learned) {
      if (!learnedDidTenantByLast10.has(row.did10)) {
        learnedDidTenantByLast10.set(row.did10, row.tenantId);
      }
    }
  }
  // PBX CDR cache linkedId-to-tenant is intentionally NOT used here.
  // The PBX main tenant contains ALL calls, so mapping via pbxTenantId
  // would incorrectly label every call as the main tenant (e.g. Gesheft).
  // Tenant resolution relies on extension, phone number, and learned DID lookups instead.

  const exactDidRule = new Map<string, string>();
  const exactFromDidRule = new Map<string, string>();
  const extensionPrefixRules: Array<{ prefix: string; tenantId: string }> = [];
  for (const rule of tenantRules) {
    const tenantRef = `vpbx:${rule.tenantSlug}`;
    if (rule.matchType === "did") exactDidRule.set(digitsOnly(rule.matchValue), tenantRef);
    else if (rule.matchType === "from_did") exactFromDidRule.set(digitsOnly(rule.matchValue), tenantRef);
    else if (rule.matchType === "extension_prefix") extensionPrefixRules.push({ prefix: digitsOnly(rule.matchValue), tenantId: tenantRef });
  }

  // --- LinkedId sibling lookup: find tenantId from other ConnectCdr rows sharing the same linkedId ---
  const nullTenantLinkedIds = Array.from(new Set(
    rows
      .filter((r) => (!r.tenantId || r.tenantId.startsWith("vpbx:")) && r.linkedId)
      .map((r) => r.linkedId)
  ));
  const siblingTenantByLinkedId = new Map<string, string>();
  if (nullTenantLinkedIds.length > 0) {
    const siblingRows = await db.connectCdr.findMany({
      where: {
        linkedId: { in: nullTenantLinkedIds },
        tenantId: { not: null },
      },
      select: { linkedId: true, tenantId: true },
      distinct: ["linkedId"],
    });
    for (const sr of siblingRows) {
      if (sr.tenantId && !sr.tenantId.startsWith("vpbx:") && !siblingTenantByLinkedId.has(sr.linkedId)) {
        siblingTenantByLinkedId.set(sr.linkedId, sr.tenantId);
      }
    }
  }

  // --- Number-to-tenant fallback: for still-unresolved rows, check ConnectCdr for same numbers with known tenant ---
  const stillUnresolvedNumbers = new Set<string>();
  for (const r of rows) {
    if (r.tenantId && !r.tenantId.startsWith("vpbx:")) continue;
    if (r.linkedId && siblingTenantByLinkedId.has(r.linkedId)) continue;
    const f = digitsOnly(r.fromNumber);
    const t = digitsOnly(r.toNumber);
    if (f.length >= 10) stillUnresolvedNumbers.add(f.slice(-10));
    if (t.length >= 10) stillUnresolvedNumbers.add(t.slice(-10));
  }
  const numberTenantFallback = new Map<string, string>();
  if (stillUnresolvedNumbers.size > 0) {
    const numList = Array.from(stillUnresolvedNumbers);
    const numListSql = numList.map((d) => `'${d.replace(/'/g, "''")}'`).join(", ");
    type NumTenantRow = { num10: string; tenantId: string };
    const numTenantRows = await db.$queryRawUnsafe<NumTenantRow[]>(`
      WITH nums AS (
        SELECT
          "tenantId",
          RIGHT(REGEXP_REPLACE(COALESCE("fromNumber", ''), '[^0-9]', '', 'g'), 10) AS num10
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '90 days'
        UNION ALL
        SELECT
          "tenantId",
          RIGHT(REGEXP_REPLACE(COALESCE("toNumber", ''), '[^0-9]', '', 'g'), 10) AS num10
        FROM "ConnectCdr"
        WHERE "tenantId" IS NOT NULL
          AND "tenantId" NOT LIKE 'vpbx:%'
          AND "startedAt" >= NOW() - INTERVAL '90 days'
      ),
      ranked AS (
        SELECT
          num10,
          "tenantId",
          COUNT(*)::bigint AS c,
          ROW_NUMBER() OVER (PARTITION BY num10 ORDER BY COUNT(*) DESC) AS rn
        FROM nums
        WHERE LENGTH(num10) = 10 AND num10 IN (${numListSql})
        GROUP BY num10, "tenantId"
      )
      SELECT num10, "tenantId"
      FROM ranked
      WHERE rn = 1
    `);
    for (const row of numTenantRows) {
      if (!numberTenantFallback.has(row.num10)) {
        numberTenantFallback.set(row.num10, row.tenantId);
      }
    }
  }

  const tenantIds = Array.from(new Set(
    [
      ...rows.map((r) => r.tenantId),
      ...Array.from(extensionTenantByExt.values()),
      ...Array.from(extensionTenantByPbxExtId.values()),
      ...Array.from(learnedExtTenantByExt.values()),
      ...Array.from(phoneTenantByLast10.values()),
      ...Array.from(ombuDidTenantByLast10.values()),
      ...Array.from(learnedDidTenantByLast10.values()),
      ...Array.from(siblingTenantByLinkedId.values()),
      ...Array.from(numberTenantFallback.values()),
    ].filter((v): v is string => Boolean(v) && !String(v).startsWith("vpbx:"))
  ));
  const tenants = tenantIds.length > 0
    ? await db.tenant.findMany({
      where: { id: { in: tenantIds } },
      select: { id: true, name: true },
    })
    : [];
  const tenantNameById = new Map<string, string>(tenants.map((t) => [t.id, t.name]));
  const pbxInst = await db.pbxInstance.findFirst({ where: { isEnabled: true }, orderBy: { updatedAt: "desc" } });
  const dirRows = pbxInst
    ? await db.pbxTenantDirectory.findMany({
        where: { pbxInstanceId: pbxInst.id },
        select: { tenantSlug: true, displayName: true, tenantCode: true, vitalTenantId: true },
      })
    : [];
  const dirDisplayBySlug = new Map<string, string>();
  const dirDisplayByVital = new Map<string, string>();
  for (const r of dirRows) {
    const label = (r.displayName || "").trim() || r.tenantCode || r.tenantSlug;
    dirDisplayBySlug.set(r.tenantSlug.toLowerCase(), label);
    dirDisplayByVital.set(r.vitalTenantId.trim(), label);
  }
  const allTenants = await db.tenant.findMany({ select: { id: true, name: true } });
  // Back-fill tenantNameById with every Connect tenant so any inference path
  // (vpbx-slug mapping, ombutel DID lookup, etc.) that resolves to a real Connect
  // tenant ID always gets a human-readable name instead of the raw UUID.
  for (const t of allTenants) {
    if (!tenantNameById.has(t.id)) tenantNameById.set(t.id, t.name);
  }
  const normalizeTenantSlug = (value: string) =>
    String(value || "")
      .toLowerCase()
      .trim()
      .replace(/[^a-z0-9]+/g, "");
  const tenantIdByNormalizedSlug = new Map<string, string>();
  for (const t of allTenants) {
    const key = normalizeTenantSlug(t.name);
    if (key && !tenantIdByNormalizedSlug.has(key)) tenantIdByNormalizedSlug.set(key, t.id);
  }
  const mapVpbxLikeTenantToConnect = (tenantLike: string | null | undefined): string | null => {
    const raw = String(tenantLike || "").trim();
    if (!raw) return null;
    const slug = raw.startsWith("vpbx:") ? raw.slice(5) : raw;
    const key = normalizeTenantSlug(slug.replace(/[_-]+/g, " "));
    return key ? (tenantIdByNormalizedSlug.get(key) || null) : null;
  };
  const dcontextToTenant = (dcontext: string | null | undefined): string | null => {
    const dc = String(dcontext || "").toLowerCase();
    if (!dc) return null;
    const m = dc.match(/ext-local-([a-z0-9_-]+)/i);
    if (!m?.[1]) return null;
    return mapVpbxLikeTenantToConnect(m[1]);
  };

  function inferTenantIdForRow(row: {
    tenantId: string | null;
    linkedId: string;
    fromNumber: string | null;
    fromName?: string | null;
    toNumber: string | null;
    dcontext?: string | null;
    pbxVitalTenantId?: string | null;
  }): string | null {
    const hasRealTenantId = row.tenantId && !row.tenantId.startsWith("vpbx:");
    if (hasRealTenantId) return row.tenantId;
    const mappedFromVpbx = mapVpbxLikeTenantToConnect(row.tenantId);
    if (mappedFromVpbx) return mappedFromVpbx;

    const fromDigits = digitsOnly(row.fromNumber);
    const toDigits = digitsOnly(row.toNumber);
    const fromExt = extractLikelyExtension(row.fromNumber);
    const toExt = extractLikelyExtension(row.toNumber);

    if (toExt && extensionTenantByExt.has(toExt)) return extensionTenantByExt.get(toExt)!;
    if (fromExt && extensionTenantByExt.has(fromExt)) return extensionTenantByExt.get(fromExt)!;
    if (toExt && extensionTenantByPbxExtId.has(toExt)) return extensionTenantByPbxExtId.get(toExt)!;
    if (fromExt && extensionTenantByPbxExtId.has(fromExt)) return extensionTenantByPbxExtId.get(fromExt)!;
    if (toExt && learnedExtTenantByExt.has(toExt)) return learnedExtTenantByExt.get(toExt)!;
    if (fromExt && learnedExtTenantByExt.has(fromExt)) return learnedExtTenantByExt.get(fromExt)!;
    if (toDigits.length >= 10) {
      const o = ombuDidTenantByLast10.get(toDigits.slice(-10));
      if (o) return o;
    }
    if (fromDigits.length >= 10) {
      const o = ombuDidTenantByLast10.get(fromDigits.slice(-10));
      if (o) return o;
    }
    if (toDigits.length >= 10) {
      const t = phoneTenantByLast10.get(toDigits.slice(-10));
      if (t) return t;
    }
    if (fromDigits.length >= 10) {
      const t = phoneTenantByLast10.get(fromDigits.slice(-10));
      if (t) return t;
    }
    if (toDigits.length >= 10) {
      const t = learnedDidTenantByLast10.get(toDigits.slice(-10));
      if (t) return t;
    }
    if (fromDigits.length >= 10) {
      const t = learnedDidTenantByLast10.get(fromDigits.slice(-10));
      if (t) return t;
    }
    if (toDigits && exactDidRule.has(toDigits)) return exactDidRule.get(toDigits)!;
    if (fromDigits && exactFromDidRule.has(fromDigits)) return exactFromDidRule.get(fromDigits)!;
    if (fromExt) {
      const prefixMatch = extensionPrefixRules.find((r) => fromExt.startsWith(r.prefix));
      if (prefixMatch) return prefixMatch.tenantId;
    }
    // Broad number-to-tenant fallback (90 days of ConnectCdr history)
    if (toDigits.length >= 10) {
      const t = numberTenantFallback.get(toDigits.slice(-10));
      if (t) return t;
    }
    if (fromDigits.length >= 10) {
      const t = numberTenantFallback.get(fromDigits.slice(-10));
      if (t) return t;
    }
    // Sibling ConnectCdr row with same linkedId that has a real tenant
    if (row.linkedId && siblingTenantByLinkedId.has(row.linkedId)) return siblingTenantByLinkedId.get(row.linkedId)!;
    // Fall back to context-derived tenant slug (e.g. ext-local-tenant_slug)
    const mappedFromContext = dcontextToTenant(row.dcontext);
    if (mappedFromContext) return mappedFromContext;
    // Fall back to the vpbx: slug if nothing better was found
    if (row.tenantId) return row.tenantId;
    return null;
  }

  const items = rows.map((r) => {
    const inferredTenantId = inferTenantIdForRow(r);
    let tenantName = "Unassigned";
    if (inferredTenantId) {
      if (!inferredTenantId.startsWith("vpbx:")) {
        tenantName = tenantNameById.get(inferredTenantId) || prettifyTenantSlugFromId(inferredTenantId);
      } else {
        const slug = inferredTenantId.slice(5).toLowerCase();
        tenantName =
          dirDisplayBySlug.get(slug) || prettifyTenantSlugFromId(inferredTenantId);
      }
    }
    if (tenantName === "Unassigned" && r.pbxVitalTenantId) {
      const dn = dirDisplayByVital.get(r.pbxVitalTenantId.trim());
      if (dn) tenantName = dn;
    }
    const outcome = deriveCallOutcome({
      disposition: r.disposition,
      direction: r.direction,
      dcontextsSeen: r.dcontextsSeen,
      channelsSeen: r.channelsSeen,
      talkSec: r.talkSec || 0,
      queueId: r.queueId,
      dcontext: r.dcontext,
    });
    return {
      callId: r.linkedId || r.id,
      rowId: r.id,
      linkedId: r.linkedId,
      fromNumber: r.fromNumber || "",
      fromName: r.fromName || null,
      toNumber: r.toNumber || "",
      direction: (["incoming", "outgoing", "internal"].includes(r.direction) ? r.direction : "incoming") as "incoming" | "outgoing" | "internal",
      status: mapDispositionToHistoryStatus(r.disposition),
      disposition: r.disposition,
      durationSec: r.durationSec || 0,
      talkSec: r.talkSec || 0,
      startedAt: r.startedAt.toISOString(),
      answeredAt: r.answeredAt?.toISOString() ?? null,
      endedAt: r.endedAt?.toISOString() ?? null,
      tenantId: inferredTenantId,
      tenantName,
      rangExtension: pickRangExtension(r.direction, r.fromNumber, r.toNumber),
      // Derived call outcome fields
      answeredByType: outcome.answeredByType,
      humanAnswered: outcome.humanAnswered,
      ivrAnswered: outcome.ivrAnswered,
      voicemailAnswered: outcome.voicemailAnswered,
      attemptedExtensions: outcome.attemptedExtensions,
      journeySummary: outcome.journeySummary,
      finalOutcomeReason: outcome.finalOutcomeReason,
      journeySteps: outcome.journeySteps,
      recordingAvailable: !!r.recordingPath,
      recordingPath: r.recordingPath ?? null,
    };
  });

  const totalPages = Math.max(1, Math.ceil(total / query.pageSize));
  return reply.send({
    items,
    total,
    showing: items.length,
    page: query.page,
    pageSize: query.pageSize,
    totalPages,
    window: {
      startIso: startAt.toISOString(),
      endIso: endAt.toISOString(),
      timezone: process.env.PBX_TIMEZONE?.trim() || "UTC",
    },
    scope: tenantIdFilter ? "tenant" : "global",
    totalsByDirection: {
      incoming,
      outgoing,
      internal,
      total,
    },
  });
});

// ─── Live DID→tenant name map (used by portal live-call display) ──────────────
// Returns the active inbound DID list with resolved Connect tenant names.
// Lightweight — one small query, result is small (< 100 rows in practice).
app.get("/calls/live-did-map", async (req, reply) => {
  const user = await requirePermission(req, reply, canViewCustomers);
  if (!user) return;

  const isSuperAdmin = String(user.role || "").toUpperCase() === "SUPER_ADMIN";

  const instance = await db.pbxInstance.findFirst({
    where: { isEnabled: true },
    orderBy: { updatedAt: "desc" },
  });
  if (!instance) return reply.send({ entries: [] });

  const allDidRows = await db.pbxTenantInboundDid.findMany({
    where: { pbxInstanceId: instance.id, active: true, connectTenantId: { not: null } },
    select: { e164: true, connectTenantId: true },
  });

  // Scope: non-super-admins only see their own tenant's DIDs
  const didRows = isSuperAdmin
    ? allDidRows
    : allDidRows.filter((r) => r.connectTenantId === (user.tenantId ?? null));

  const tenantIds = [...new Set(didRows.map((r) => r.connectTenantId).filter(Boolean) as string[])];

  const tenants = tenantIds.length > 0
    ? await db.tenant.findMany({ where: { id: { in: tenantIds } }, select: { id: true, name: true } })
    : [];

  const nameById = new Map<string, string>(tenants.map((t) => [t.id, t.name]));

  const entries = didRows.map((r) => ({
    e164: r.e164,
    tenantId: r.connectTenantId as string,
    tenantName: nameById.get(r.connectTenantId as string) ?? "Unknown tenant",
  }));

  return reply.send({ entries });
});

app.get("/billing/sola/config", async (req, reply) => {
  const admin = await requirePermission(req, reply, canManageBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const record = await db.billingSolaConfig.findUnique({ where: { tenantId: admin.tenantId } });
  if (!record) {
    return { configured: false, config: null };
  }

  try {
    const resolved = await getTenantSolaConfig(admin.tenantId, { requireEnabled: false, allowFallbackEnv: false });
    return { configured: true, config: resolved.masked };
  } catch {
    return {
      configured: true,
      config: {
        id: record.id,
        tenantId: record.tenantId,
        configured: true,
        isEnabled: !!record.isEnabled,
        apiBaseUrl: record.apiBaseUrl,
        mode: record.mode === "PROD" ? "prod" : "sandbox",
        simulate: !!record.simulate,
        authMode: record.authMode === "AUTHORIZATION_HEADER" ? "authorization_header" : "xkey_body",
        authHeaderName: record.authHeaderName || null,
        pathOverrides: normalizeSolaPathOverrides(record.pathOverrides || {}),
        masked: { apiKey: null, apiSecret: null, webhookSecret: null, ifieldsKey: null },
        status: {
          lastTestAt: record.lastTestAt,
          lastTestResult: record.lastTestResult || null,
          lastTestErrorCode: record.lastTestErrorCode || null
        },
        meta: {
          createdAt: record.createdAt,
          updatedAt: record.updatedAt,
          createdByUserId: record.createdByUserId,
          updatedByUserId: record.updatedByUserId
        }
      }
    };
  }
});

app.put("/billing/sola/config", async (req, reply) => {
  const admin = await requirePermission(req, reply, canManageBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const input = z.object({
    apiBaseUrl: z.string().url(),
    mode: z.enum(["sandbox", "prod"]),
    simulate: z.boolean().default(false),
    authMode: z.enum(["xkey_body", "authorization_header"]),
    authHeaderName: z.string().min(1).max(64).optional().nullable(),
    apiKey: z.string().min(1).optional(),
    apiSecret: z.string().min(1).optional().nullable(),
    webhookSecret: z.string().min(1).optional().nullable(),
    ifieldsKey: z.string().min(1).optional().nullable(),
    pathOverrides: z.object({
      customerPath: z.string().min(1).optional(),
      subscriptionPath: z.string().min(1).optional(),
      transactionPath: z.string().min(1).optional(),
      hostedSessionPath: z.string().min(1).optional(),
      chargePath: z.string().min(1).optional(),
      cancelPath: z.string().min(1).optional()
    }).optional()
  }).parse(req.body || {});

  if (input.mode === "prod" && input.simulate) {
    return reply.status(400).send({ error: "INVALID_MODE", message: "simulate must be disabled when mode=prod" });
  }

  const existing = await db.billingSolaConfig.findUnique({ where: { tenantId: admin.tenantId } });
  let existingSecrets: BillingSolaCredentialPayload = { apiKey: "", apiSecret: null, webhookSecret: null, ifieldsKey: null };
  if (existing) {
    try {
      existingSecrets = decryptJson<BillingSolaCredentialPayload>(existing.credentialsEncrypted);
    } catch {
      return reply.status(400).send({ error: "SOLA_DECRYPT_FAILED" });
    }
  }

  const nextSecrets: BillingSolaCredentialPayload = {
    apiKey: input.apiKey || existingSecrets.apiKey || "",
    apiSecret: input.apiSecret !== undefined ? (input.apiSecret || null) : (existingSecrets.apiSecret || null),
    webhookSecret: input.webhookSecret !== undefined ? (input.webhookSecret || null) : (existingSecrets.webhookSecret || null),
    ifieldsKey: input.ifieldsKey !== undefined ? (input.ifieldsKey || null) : (existingSecrets.ifieldsKey || null)
  };

  if (!nextSecrets.apiKey) {
    return reply.status(400).send({ error: "SOLA_API_KEY_REQUIRED" });
  }

  const encrypted = encryptJson(nextSecrets);
  const pathOverrides = normalizeSolaPathOverrides(input.pathOverrides || existing?.pathOverrides || {});
  const isEnabled = false;

  const upserted = await db.billingSolaConfig.upsert({
    where: { tenantId: admin.tenantId },
    create: {
      tenantId: admin.tenantId,
      apiBaseUrl: input.apiBaseUrl,
      mode: input.mode === "prod" ? "PROD" : "SANDBOX",
      simulate: input.simulate,
      authMode: input.authMode === "authorization_header" ? "AUTHORIZATION_HEADER" : "XKEY_BODY",
      authHeaderName: input.authHeaderName || null,
      pathOverrides: pathOverrides as any,
      credentialsEncrypted: encrypted,
      credentialsKeyId: "v1",
      isEnabled,
      createdByUserId: admin.sub,
      updatedByUserId: admin.sub,
      lastTestResult: null,
      lastTestErrorCode: null,
      lastTestAt: null
    },
    update: {
      apiBaseUrl: input.apiBaseUrl,
      mode: input.mode === "prod" ? "PROD" : "SANDBOX",
      simulate: input.simulate,
      authMode: input.authMode === "authorization_header" ? "AUTHORIZATION_HEADER" : "XKEY_BODY",
      authHeaderName: input.authHeaderName || null,
      pathOverrides: pathOverrides as any,
      credentialsEncrypted: encrypted,
      credentialsKeyId: "v1",
      isEnabled,
      updatedByUserId: admin.sub,
      lastTestResult: null,
      lastTestErrorCode: null,
      lastTestAt: null
    }
  });

  await audit({
    tenantId: admin.tenantId,
    actorUserId: admin.sub,
    action: existing ? "SOLA_CREDENTIAL_UPDATED" : "SOLA_CREDENTIAL_CREATED",
    entityType: "BillingSolaConfig",
    entityId: upserted.id
  });

  const masked = maskSolaConfigForResponse({ record: upserted, secrets: nextSecrets, pathOverrides });
  return { ok: true, config: masked };
});

app.post("/billing/sola/config/test", async (req, reply) => {
  const admin = await requirePermission(req, reply, canManageBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  let resolved: { source: "TENANT" | "ENV"; adapterConfig: SolaCardknoxConfig; record: any | null; masked: any | null };
  try {
    resolved = await getTenantSolaConfig(admin.tenantId, { requireEnabled: false, allowFallbackEnv: false });
  } catch (e: any) {
    const code = String(e?.code || "NOT_CONFIGURED");
    return reply.status(400).send({ error: code });
  }

  try {
    const result = await getSolaAdapter(resolved.adapterConfig).testConnection();
    const updated = await db.billingSolaConfig.update({
      where: { tenantId: admin.tenantId },
      data: { lastTestAt: new Date(), lastTestResult: "SUCCESS", lastTestErrorCode: null, updatedByUserId: admin.sub }
    });
    await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "SOLA_CREDENTIAL_TESTED_SUCCESS", entityType: "BillingSolaConfig", entityId: updated.id });
    return { ok: true, simulated: result.simulated, code: "OK" };
  } catch (e: any) {
    const code = String(e?.code || "SOLA_VALIDATION_FAILED");
    const updated = await db.billingSolaConfig.update({
      where: { tenantId: admin.tenantId },
      data: { lastTestAt: new Date(), lastTestResult: "FAILED", lastTestErrorCode: code, updatedByUserId: admin.sub }
    });
    await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "SOLA_CREDENTIAL_TESTED_FAILED", entityType: "BillingSolaConfig", entityId: updated.id });
    return reply.status(400).send({ error: "SOLA_VALIDATION_FAILED", code });
  }
});

app.post("/billing/sola/config/enable", async (req, reply) => {
  const admin = await requirePermission(req, reply, canManageBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const record = await db.billingSolaConfig.findUnique({ where: { tenantId: admin.tenantId } });
  if (!record) return reply.status(404).send({ error: "NOT_CONFIGURED" });
  if (record.lastTestResult !== "SUCCESS") {
    return reply.status(400).send({ error: "SOLA_TEST_REQUIRED", message: "Run test connection successfully before enabling." });
  }

  const updated = await db.billingSolaConfig.update({ where: { tenantId: admin.tenantId }, data: { isEnabled: true, updatedByUserId: admin.sub } });
  await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "SOLA_CREDENTIAL_ENABLED", entityType: "BillingSolaConfig", entityId: updated.id });
  return { ok: true, isEnabled: true, updatedAt: updated.updatedAt };
});

app.post("/billing/sola/config/disable", async (req, reply) => {
  const admin = await requirePermission(req, reply, canManageBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const record = await db.billingSolaConfig.findUnique({ where: { tenantId: admin.tenantId } });
  if (!record) return reply.status(404).send({ error: "NOT_CONFIGURED" });

  const updated = await db.billingSolaConfig.update({ where: { tenantId: admin.tenantId }, data: { isEnabled: false, updatedByUserId: admin.sub } });
  await audit({ tenantId: admin.tenantId, actorUserId: admin.sub, action: "SOLA_CREDENTIAL_DISABLED", entityType: "BillingSolaConfig", entityId: updated.id });
  return { ok: true, isEnabled: false, updatedAt: updated.updatedAt };
});

app.get("/admin/billing/sola/tenants", async (req, reply) => {
  const admin = await requirePermission(req, reply, canAccessAdminBilling);
  if (!admin) return;

  const rows = await db.tenant.findMany({
    select: {
      id: true,
      name: true,
      billingSolaConfig: { select: { id: true, isEnabled: true, mode: true, simulate: true, lastTestAt: true, lastTestResult: true, lastTestErrorCode: true, updatedAt: true } }
    },
    orderBy: { createdAt: "desc" }
  });

  return rows.map((r) => ({
    tenantId: r.id,
    tenantName: r.name,
    configured: !!r.billingSolaConfig,
    isEnabled: !!r.billingSolaConfig?.isEnabled,
    mode: r.billingSolaConfig ? (r.billingSolaConfig.mode === "PROD" ? "prod" : "sandbox") : null,
    simulate: r.billingSolaConfig ? !!r.billingSolaConfig.simulate : null,
    lastTestAt: r.billingSolaConfig?.lastTestAt || null,
    lastTestResult: r.billingSolaConfig?.lastTestResult || null,
    lastTestErrorCode: r.billingSolaConfig?.lastTestErrorCode || null,
    updatedAt: r.billingSolaConfig?.updatedAt || null
  }));
});

app.get("/admin/billing/sola/tenant/:id", async (req, reply) => {
  const admin = await requirePermission(req, reply, canAccessAdminBilling);
  if (!admin) return;
  if (!ensureCredentialCrypto(reply)) return;

  const { id } = req.params as { id: string };
  const tenant = await db.tenant.findUnique({ where: { id }, select: { id: true, name: true } });
  if (!tenant) return reply.status(404).send({ error: "tenant_not_found" });

  const record = await db.billingSolaConfig.findUnique({ where: { tenantId: id } });
  if (!record) return { tenantId: tenant.id, tenantName: tenant.name, configured: false, config: null };

  try {
    const resolved = await getTenantSolaConfig(id, { requireEnabled: false, allowFallbackEnv: false });
    return { tenantId: tenant.id, tenantName: tenant.name, configured: true, config: resolved.masked };
  } catch {
    return { tenantId: tenant.id, tenantName: tenant.name, configured: true, config: null };
  }
});

