// ─────────────────────────────────────────────────────────────────────────────
// Deploy Center — proxy to ops/deploy-queue (localhost:3910)
//
// Rules enforced here:
//  • SUPER_ADMIN only (via requireSuperAdmin).
//  • DEPLOY_QUEUE_TOKEN is read from env server-side; NEVER forwarded to
//    the browser in any response body or header.
//  • Only the six specific deploy-queue paths are proxied — no arbitrary URL.
//  • The log sub-path only accepts a jobId from the URL, never a raw path.
// ─────────────────────────────────────────────────────────────────────────────

const deployQueueBase = (process.env.DEPLOY_QUEUE_URL ?? "http://127.0.0.1:3910").replace(/\/$/, "");
const deployQueueToken = process.env.DEPLOY_QUEUE_TOKEN ?? "";

async function dqFetch(path: string, opts: { method?: string; body?: string } = {}): Promise<{ ok: boolean; status: number; data: unknown }> {
  if (!deployQueueToken) {
    return { ok: false, status: 503, data: { error: "deploy_queue_token_not_configured" } };
  }
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), 10_000);
  try {
    const res = await fetch(`${deployQueueBase}${path}`, {
      method: opts.method ?? "GET",
      headers: {
        "content-type": "application/json",
        "x-deploy-queue-token": deployQueueToken,
      },
      body: opts.body,
      signal: ctrl.signal,
    });
    let data: unknown;
    try { data = await res.json(); } catch { data = { error: "invalid_response_from_queue" }; }
    return { ok: res.ok, status: res.status, data };
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    if (msg.includes("abort") || msg.includes("signal")) {
      return { ok: false, status: 504, data: { error: "deploy_queue_timeout" } };
    }
    return { ok: false, status: 502, data: { error: "deploy_queue_unreachable", detail: msg } };
  } finally {
    clearTimeout(t);
  }
}

// GET /admin/deploy/status
app.get("/admin/deploy/status", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const r = await dqFetch("/ops/deploy/status");
  return reply.status(r.status).send(r.data);
});

// GET /admin/deploy/jobs?status=…&limit=…
app.get("/admin/deploy/jobs", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const qs = req.query as Record<string, string>;
  const params = new URLSearchParams();
  if (qs.status) params.set("status", qs.status);
  if (qs.limit) params.set("limit", qs.limit);
  const path = `/ops/deploy/jobs${params.toString() ? `?${params.toString()}` : ""}`;
  const r = await dqFetch(path);
  return reply.status(r.status).send(r.data);
});

// GET /admin/deploy/jobs/:id
app.get("/admin/deploy/jobs/:id", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const { id } = req.params as { id: string };
  if (!/^[0-9a-f-]{36}$/.test(id)) return reply.status(400).send({ error: "invalid_job_id" });
  const r = await dqFetch(`/ops/deploy/jobs/${encodeURIComponent(id)}`);
  return reply.status(r.status).send(r.data);
});

// GET /admin/deploy/jobs/:id/log?lines=…
app.get("/admin/deploy/jobs/:id/log", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const { id } = req.params as { id: string };
  if (!/^[0-9a-f-]{36}$/.test(id)) return reply.status(400).send({ error: "invalid_job_id" });
  const qs = req.query as Record<string, string>;
  const lines = Math.min(2000, Math.max(1, Number(qs.lines) || 200));
  const r = await dqFetch(`/ops/deploy/jobs/${encodeURIComponent(id)}/log?lines=${lines}`);
  return reply.status(r.status).send(r.data);
});

// POST /admin/deploy/enqueue
app.post("/admin/deploy/enqueue", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const body = req.body as Record<string, unknown>;
  const { service, branch, commitHash, dryRun, reason } = body;
  const requestedBy = `${admin.email ?? admin.sub} (Deploy Center)`;
  const payload = JSON.stringify({ service, branch, commitHash, requestedBy, reason, dryRun });
  const r = await dqFetch("/ops/deploy/enqueue", { method: "POST", body: payload });
  if (r.ok) {
    try {
      await audit({
        tenantId: admin.tenantId,
        actorUserId: admin.sub,
        action: dryRun ? "DEPLOY_DRY_RUN_ENQUEUED" : "DEPLOY_ENQUEUED",
        entityType: "DeployJob",
        entityId: (r.data as { job?: { id?: string } })?.job?.id ?? "unknown",
      });
    } catch {
      app.log.warn("deploy audit log failed (non-blocking)");
    }
  }
  return reply.status(r.status).send(r.data);
});

// POST /admin/deploy/jobs/:id/cancel
app.post("/admin/deploy/jobs/:id/cancel", async (req, reply) => {
  const admin = await requireSuperAdmin(req, reply);
  if (!admin) return;
  const { id } = req.params as { id: string };
  if (!/^[0-9a-f-]{36}$/.test(id)) return reply.status(400).send({ error: "invalid_job_id" });
  const r = await dqFetch(`/ops/deploy/jobs/${encodeURIComponent(id)}/cancel`, { method: "POST" });
  if (r.ok) {
    try {
      await audit({
        tenantId: admin.tenantId,
        actorUserId: admin.sub,
        action: "DEPLOY_JOB_CANCELLED",
        entityType: "DeployJob",
        entityId: id,
      });
    } catch {
      app.log.warn("deploy cancel audit log failed (non-blocking)");
    }
  }
  return reply.status(r.status).send(r.data);
});

// ── Startup telephony/WebRTC config validation ────────────────────────────────
// Runs just before listen so logs appear during startup, not at module load.
const port = Number(process.env.PORT || 3001);
(async () => {
  // Validate and log telephony env vars at startup.
  // This makes missing-config problems immediately visible in container logs.
  const missingAtStart: string[] = [];

  if (!pbxWsEndpoint) {
    missingAtStart.push("PBX_WS_ENDPOINT");
    app.log.warn(
      "PBX_WS_ENDPOINT is NOT set — browser/mobile WebRTC will not know where to connect. " +
      "Set PBX_WS_ENDPOINT=wss://209.145.60.79:8089/ws"
    );
  } else {
    // Reject insecure or stale endpoints
    if (pbxWsEndpoint.startsWith("ws://")) {
      app.log.warn({ pbxWsEndpoint }, "PBX_WS_ENDPOINT uses insecure ws:// — browsers require wss://");
    } else if (pbxWsEndpoint.includes(":8088") || pbxWsEndpoint.includes(":5060")) {
      app.log.warn({ pbxWsEndpoint }, "PBX_WS_ENDPOINT port looks stale — expected :8089/ws");
    } else {
      app.log.info({ pbxWsEndpoint }, "PBX WebSocket endpoint OK");
    }
  }

  if (!turnServerEnv) {
    app.log.warn(
      "TURN_SERVER is NOT set — audio will likely fail for users behind strict/symmetric NAT. " +
      "Install coturn on the backend server and set TURN_SERVER, TURN_USERNAME, TURN_PASSWORD."
    );
  } else {
    app.log.info(
      {
        turnServer: turnServerEnv,
        authMode: turnAuthSecretEnv ? "hmac-use-auth-secret" : "static-credentials",
        turnAuthSecret: turnAuthSecretEnv ? "(set)" : "(not set)",
        turnUsername: !turnAuthSecretEnv && turnUsernameEnv ? "(set)" : "(not set — using hmac)",
        turnPassword: !turnAuthSecretEnv && turnPasswordEnv ? "(set)" : "(not set — using hmac)",
      },
      "TURN server configured"
    );
  }

  app.log.info(
    { stunServer: stunServerEnv },
    "STUN server configured"
  );

  if (missingAtStart.length > 0) {
    app.log.warn({ missingAtStart }, "WebRTC provisioning is INCOMPLETE — see warnings above");
  } else {
    app.log.info("WebRTC telephony env config OK");
  }

  await registerBillingRoutes(app);
  await registerPlatformRolePermissionRoutes(app);
  registerUserExtensionProvisioningRoutes(app, {
    getUser: getUser as any,
    requirePermission: requirePermission as any,
    canManageUsers: canManageUsers as any,
    resolveManagedTenant: resolveManagedTenant as any,
    // Wrap the real sync signature (db, pbxInstanceId, client, options) into a
    // tenantId-only callable. Returns a no-op result if the tenant has no PBX
    // link, so an admin clicking "Re-sync credentials" never crashes.
    syncExtensionsFromPbx: async (tenantId: string) => {
      const link = await db.tenantPbxLink.findUnique({
        where: { tenantId },
        include: { pbxInstance: true },
      });
      if (!link) return { skipped: "pbx_not_linked" };
      const auth = decryptJson<{ token: string; secret?: string }>(link.pbxInstance.apiAuthEncrypted);
      const vital = getVitalPbxClient({ baseUrl: link.pbxInstance.baseUrl, token: auth.token, secret: auth.secret });
      const vitalTenantId = link.pbxTenantId || undefined;
      return syncExtensionsFromPbx(db, link.pbxInstanceId, vital, vitalTenantId ? { vitalTenantId } : undefined);
    },
    audit: audit as any,
    encryptJson,
    resetSipPasswordOnPbx: async (linkId) => {
      const link = await db.pbxExtensionLink.findUnique({
        where: { id: linkId },
        include: { tenant: { select: { id: true } } },
      });
      if (!link) return null;
      const tenantPbxLink = await db.tenantPbxLink.findUnique({
        where: { tenantId: link.tenantId },
        include: { pbxInstance: true },
      });
      if (!tenantPbxLink) return null;
      const auth = decryptJson<{ token: string; secret?: string }>(
        tenantPbxLink.pbxInstance.apiAuthEncrypted,
      );
      const out = await getWirePbxClient({
        baseUrl: tenantPbxLink.pbxInstance.baseUrl,
        token: auth.token,
        secret: auth.secret,
      }).resetPassword(link.pbxExtensionId);
      return { sipPassword: out.sipPassword };
    },
  });
  registerConnectChatRoutes(app, { smsQueue });
  await app.listen({ host: "0.0.0.0", port });
  startPbxKpiBackgroundRefresh();
})().catch((e) => {
  app.log.error(e);
  process.exit(1);
});
